INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VPH_2022_consolidated', 'VPH', 2022, 'consolidated', 'Công ty có nhiều giao dịch phức tạp với các bên liên quan, bao gồm cho vay với lãi suất cao (9-10%/năm), mượn tiền không lãi suất từ công ty liên kết (Công ty CP Tấn Lực), chuyển nhượng quyền sử dụng đất với cá nhân là nhân sự quản lý. Các giao dịch này có thể tiềm ẩn rủi ro về tính công bằng và minh bạch, đặc biệt khi giao dịch không có tài sản đảm bảo hoặc lãi suất ưu đãi không rõ ràng.', 'Áp lực nợ ngắn hạn rất lớn với tổng nợ ngắn hạn trên 1.220 tỷ VND, trong đó nợ vay chiếm trên 528 tỷ VND. Lãi suất vay dao động từ 8-12%/năm, chủ yếu vay từ ngân hàng và tổ chức cá nhân. Công ty phải thế chấp quyền sử dụng đất để vay ngân hàng, cho thấy đòn bẩy tài chính cao và rủi ro thanh khoản nếu dòng tiền từ hoạt động kinh doanh không đủ.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang (dự án bất động sản) với giá trị trên 1.012 tỷ VND, tăng mạnh so với đầu năm. Nhiều dự án đang trong giai đoạn triển khai, tiềm ẩn rủi ro ứ đọng nếu thị trường bất động sản suy giảm hoặc tiến độ dự án bị chậm. Không có dự phòng giảm giá hàng tồn kho.', 7, 'Công ty Vạn Phát Hưng hoạt động trong lĩnh vực bất động sản với nhiều dự án đang triển khai. Tình hình tài chính có áp lực nợ ngắn hạn lớn, phụ thuộc nhiều vào vốn vay và giao dịch bên liên quan. Dòng tiền hoạt động kinh doanh năm 2022 dương nhưng không đủ bù đắp dòng tiền đầu tư và tài chính. Công ty có nhiều giao dịch với bên liên quan phức tạp, cần giám sát chặt chẽ. Triển vọng phụ thuộc vào tiến độ dự án và khả năng huy động vốn.'),
('VPH_2020_consolidated', 'VPH', 2020, 'consolidated', 'Công ty có nhiều giao dịch phức tạp với bên liên quan, bao gồm cho vay không lãi suất cho nhân sự quản lý (ông Võ Nguyễn Như Nguyên, bà Nguyễn Thị Hương Thảo), mua bán tài sản, đặt cọc mua đất thông qua cá nhân. Điều này tiềm ẩn rủi ro xung đột lợi ích và thiếu minh bạch trong giao dịch.', 'Nợ vay tăng mạnh từ 283 tỷ lên 435 tỷ VNĐ, chủ yếu là nợ ngắn hạn. Tỷ lệ nợ trên tài sản là 50.3%. Tài sản thế chấp chủ yếu là quyền sử dụng đất và dự án bất động sản, có rủi ro giảm giá trị. Áp lực trả nợ ngắn hạn lớn.', 'Hàng tồn kho tăng từ 533 tỷ lên 760 tỷ VNĐ, chủ yếu là chi phí dở dang các dự án bất động sản. Nhiều dự án dở dang (Nhơn Đức, Quận 2, Long Trường...) cần vốn đầu tư thêm và có thể bị ảnh hưởng bởi biến động thị trường bất động sản.', 7, 'Công ty kinh doanh bất động sản, doanh thu tăng nhưng lợi nhuận giảm do chi phí tài chính tăng mạnh và giảm giá hàng bán. Nợ vay tăng cao, dòng tiền hoạt động kinh doanh âm. Hàng tồn kho dở dang lớn, tập trung ở nhiều dự án. Công ty có giao dịch phức tạp với bên liên quan. Triển vọng phụ thuộc vào khả năng bán hàng tồn kho và tình hình thị trường bất động sản.'),
('VPH_2021_parent', 'VPH', 2021, 'parent', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, bao gồm công ty con, công ty liên kết và các nhân sự quản lý chủ chốt. Các giao dịch chủ yếu là vay mượn tiền, cung cấp dịch vụ và hợp tác kinh doanh. Cần đánh giá tính minh bạch và công bằng của các giao dịch này, đặc biệt với lãi suất cao (10-15%/năm) cho một số khoản vay từ cá nhân.', 'Doanh nghiệp có mức nợ vay ngắn hạn lớn (hơn 564 tỷ VNĐ) với lãi suất cao, đặc biệt từ các cá nhân (12-15%/năm). Áp lực trả nợ và lãi vay là đáng kể. Tuy nhiên, doanh nghiệp có tài sản đảm bảo cho một số khoản vay ngân hàng và dòng tiền kinh doanh dương.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang cho các dự án bất động sản, trị giá hơn 353 tỷ VNĐ. Rủi ro ứ đọng dự án do chậm tiến độ hoặc thị trường bất động sản suy giảm. Không có dự phòng giảm giá được trích lập.', 7, 'Công ty Cổ phần Vạn phát Hưng hoạt động trong lĩnh vực bất động sản với nhiều dự án lớn. Tình hình tài chính có áp lực nợ vay cao, đặc biệt nợ ngắn hạn từ các cá nhân với lãi suất lớn. Doanh thu và lợi nhuận giảm so với năm trước, nhưng dòng tiền kinh doanh vẫn dương. Các giao dịch với bên liên quan phức tạp, cần giám sát chặt chẽ. Triển vọng đầu tư trung bình, phụ thuộc vào tiến độ dự án và thị trường bất động sản.'),
('VPH_2020_parent', 'VPH', 2020, 'parent', 'Doanh nghiệp có nhiều giao dịch phức tạp với các bên liên quan, bao gồm cho vay không lãi suất (khoản cho vay ông Võ Hoàng Thạnh), mượn tài sản đảm bảo cho công ty khác vay vốn, và các giao dịch mua bán, góp vốn nội bộ giữa công ty mẹ và công ty con. Điều này tiềm ẩn rủi ro về xung đột lợi ích và minh bạch tài chính.', 'Áp lực nợ vay ngắn hạn rất lớn với tổng nợ ngắn hạn lên đến 307.444 tỷ VNĐ, chủ yếu vay từ ngân hàng, tổ chức và cá nhân với lãi suất từ 6-15%/năm. Công ty có tài sản thế chấp là quyền sử dụng đất và trái phiếu ngân hàng, nhưng khả năng thanh toán ngắn hạn bị ảnh hưởng bởi dòng tiền từ hoạt động kinh doanh giảm mạnh.', 'Hàng tồn kho dở dang (chi phí sản xuất kinh doanh dở dang) chiếm tỷ trọng lớn, tập trung ở nhiều dự án bất động sản. Một số dự án có thể bị tồn đọng do khó khăn thị trường, đặc biệt dự án Nhơn Đức đã phải điều chỉnh hồi tố giảm giá vốn. Không có dự phòng giảm giá hàng tồn kho.', 7, 'Công ty gặp khó khăn về tài chính với lợi nhuận sau thuế giảm 61% so với cùng kỳ, dòng tiền từ hoạt động kinh doanh âm, nợ ngắn hạn cao. Các giao dịch bên liên quan phức tạp làm tăng rủi ro quản trị. Triển vọng đầu tư phụ thuộc vào khả năng tiêu thụ tồn kho và tái cơ cấu nợ.'),
('VPH_2019_parent', 'VPH', 2019, 'parent', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, bao gồm công ty con, công ty liên kết và thành viên quản lý. Các giao dịch chủ yếu là cho vay, nhận vay và thanh toán dịch vụ. Không có dấu hiệu giao dịch bất thường rõ ràng nhưng mức độ phức tạp cao.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn (274.5 tỷ VND), áp lực trả nợ cao. Công ty có vay từ ngân hàng và nhiều cá nhân khác với lãi suất từ 8.5%-15%/năm. Một phần nợ được đảm bảo bằng quyền sử dụng đất và tài sản gắn liền với đất từ dự án La Casa.', 'Hàng tồn kho lớn (459.8 tỷ VND), chủ yếu là chi phí sản xuất kinh doanh dở dang từ các dự án bất động sản. Các dự án có quy mô lớn, thời gian triển vọng dài, tiềm ẩn rủi ro ứ đọng vốn nếu thị trường bất động sản suy giảm.', 5, 'Doanh nghiệp có quy mô tài sản lớn (1.814 tỷ VND), hoạt động chủ yếu trong lĩnh vực bất động sản và xây dựng. Doanh thu giảm mạnh so với năm trước (từ 704.9 tỷ xuống 158.9 tỷ VND), cho thấy sự biến động lớn trong hoạt động kinh doanh. Công ty có mối quan hệ phức tạp với các bên liên quan và mức nợ vay cao. Điểm rủi ro quản trị ở mức trung bình do có nhiều giao dịch với bên liên quan nhưng chưa phát hiện sai phạm.'),
('VPH_2021_consolidated', 'VPH', 2021, 'consolidated', 'Công ty có nhiều giao dịch phức tạp với các bên liên quan. Đáng chú ý: (1) Công ty CP Quản lý Việt Hưng cho Công ty CP BĐS Nhà Bè (công ty con) và Công ty VPH mượn tổng cộng 81 tỷ VNĐ với lãi suất 0% và không có tài sản đảm bảo; (2) Bà Nguyễn Thị Hương Thảo (Phó TGĐ) đặt cọc mua đất 285,4 tỷ VNĐ; (3) Nhiều khoản vay cá nhân từ ban lãnh đạo với lãi suất 12-15%/năm cao hơn thị trường. Các giao dịch này tạo rủi ro xung đột lợi ích và quản trị yếu kém.', 'Tổng nợ vay ngắn hạn 424,2 tỷ VNĐ, trong đó nợ cá nhân chiếm 117,6 tỷ (27,7%) với lãi suất 12-15%/năm cao hơn đáng kể so với vay ngân hàng (7.4-10%/năm). Áp lực trả nợ ngắn hạn lớn. Tài sản đảm bảo chủ yếu là quyền sử dụng đất tại các dự án. Công ty có cơ cấu nợ ngắn hạn chiếm tỷ trọng tuyệt đối, tạo rủi ro thanh khoản.', 'Hàng tồn kho chủ yếu là chi phí SXKD dở dang 392,2 tỷ VNĐ phân bổ cho nhiều dự án bất động sản. Không có dự phòng giảm giá được trích lập. Việc đình chỉ kinh doanh bất động sản tại dự án Nhơn Đức (6 tháng đầu 2021) có thể ảnh hưởng đến tiến độ triển khai và khả năng thu hồi vốn. Nhiều dự án dang dở kéo dài tiềm ẩn rủi ro ứ đọng vốn.', 7, 'Năm 2021, Công ty đạt kết quả kinh doanh ấn tượng với lợi nhuận sau thuế 83,4 tỷ VNĐ, tăng 6,11 lần so với năm 2020, chủ yếu nhờ lãi từ thoái vốn 55% cổ phần Công ty CP Đầu tư TM DV An Hưng (63,6 tỷ VNĐ). Tuy nhiên, cơ cấu tài chính có nhiều rủi ro: (1) Nợ ngắn hạn 424 tỷ VNĐ với tỷ trọng vay cá nhân lãi suất cao; (2) Hàng tồn kho dở dang lớn 392 tỷ VNĐ không có dự phòng; (3) Giao dịch bên liên quan phức tạp, đặc biệt khoản cho mượn không lãi suất 81 tỷ VNĐ. Đình chỉ kinh doanh BĐS tại dự án Nhơn Đức được miễn áp dụng 6 tháng cuối 2021, Công ty duy trì giả định hoạt động liên tục. Triển vọng phụ thuộc vào khả năng triển khai dự án và xử lý áp lực nợ vay.'),
('VPH_2019_consolidated', 'VPH', 2019, 'consolidated', 'Công ty có mối quan hệ phức tạp với nhiều bên liên quan là các công ty liên kết, công ty con và cá nhân thành viên quản lý. Có nhiều giao dịch vay mượn, tạm ứng, đặt cọc và chi hộ với giá trị lớn, một số khoản không có tài sản đảm bảo hoặc lãi suất thấp/không lãi suất. Đặc biệt, các khoản tạm ứng cho nhân viên và cá nhân để mua quyền sử dụng đất, nhà ở hình thành từ nguồn tạm ứng chưa được chuyển giao cho Công ty, tạo ra rủi ro về quyền sở hữu và thu hồi vốn. Các giao dịch mua bán tài sản, cung cấp dịch vụ với các công ty liên kết có thể không phản ánh giá thị trường, tiềm ẩn rủi ro chuyển giá.', 'Công ty có cấu trúc nợ vay lớn với tổng nợ ngắn hạn và dài hạn lên tới hàng trăm tỷ đồng. Đáng chú ý là một khoản vay lớn tại Ngân hàng Nông nghiệp được thế chấp bằng dự án bất động sản (La Casa) và tài sản hình thành từ tạm ứng của cá nhân. Nợ vay từ các cá nhân và công ty liên kết chiếm tỷ trọng đáng kể, với lãi suất từ 10% đến 15%/năm. Áp lực trả nợ ngắn hạn cao, đặc biệt là các khoản vay đến hạn trả trong 12 tháng tới. Khả năng thanh toán phụ thuộc vào dòng tiền từ hoạt động kinh doanh và thu hồi các khoản phải thu lớn.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang cho các dự án bất động sản (trên 500 tỷ đồng) và chi phí xây dựng cơ bản dở dang. Các dự án này đang trong quá trình triển khai và chưa có dự phòng giảm giá. Rủi ro đến từ việc dự án bị đình trệ, chậm tiến độ, hoặc thị trường bất động sản suy giảm dẫn đến giá trị tồn kho sụt giảm. Một phần đáng kể tài sản dở dang là chi phí cho dự án Hiệp Phước và các dự án khác, cần theo dõi tiến độ và khả năng chuyển đổi thành doanh thu.', 8, 'Tình hình tài chính của Công ty trong năm 2019 cho thấy doanh thu và lợi nhuận giảm mạnh so với năm trước (doanh thu thuần giảm 75%). Lợi nhuận gộp biên vẫn ở mức cao (52,7%) nhưng bị ảnh hưởng bởi chi phí tài chính lớn (chủ yếu là lãi vay) và phân bổ lợi thế thương mại. Công ty có tỷ lệ nợ vay cao, dòng tiền hoạt động kinh doanh dương nhưng không đủ bù đắp dòng tiền đầu tư và tài chính âm, dẫn đến giảm tiền mặt. Các rủi ro lớn bao gồm: (1) Mối quan hệ tài chính phức tạp và giá trị lớn với các bên liên quan, đặc biệt là các khoản tạm ứng và cho vay không lãi suất; (2) Áp lực trả nợ vay lớn, phụ thuộc vào tiến độ bán hàng và thu hồi công nợ từ các dự án bất động sản; (3) Hàng tồn kho dự án lớn, chưa có dự phòng, chịu rủi ro thị trường. Ban lãnh đạo cam đoan hoạt động liên tục, nhưng nhà đầu tư cần thận trọng theo dõi tiến độ các dự án, khả năng huy động vốn và quản trị rủi ro liên quan đến các giao dịch với bên liên quan.'),
('VPH_2018_consolidated', 'VPH', 2018, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với bên liên quan phức tạp, bao gồm cho vay không lãi suất hoặc lãi suất thấp, tạm ứng lớn cho cá nhân là thành viên quản lý, và giao dịch mua bán với các công ty liên kết. Điều này tiềm ẩn rủi ro về xung đột lợi ích và quản trị công ty.', 'Nợ vay ngắn hạn và dài hạn lớn, chủ yếu từ ngân hàng và cá nhân. Tài sản thế chấp là các dự án bất động sản, có rủi ro nếu thị trường suy giảm. Công ty có áp lực trả nợ đáng kể, đặc biệt nợ ngắn hạn tăng mạnh.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang (dự án bất động sản) với giá trị lớn. Nếu dự án bị đình trệ hoặc thị trường bất động sản khó khăn, giá trị tồn kho có thể bị giảm và ảnh hưởng đến dòng tiền.', 8, 'Công ty có quy mô tài sản lớn, tập trung vào kinh doanh bất động sản. Lợi nhuận giảm so với năm trước. Cơ cấu tài chính có nhiều rủi ro do nợ vay cao và giao dịch bên liên quan phức tạp. Cần theo dõi sát khả năng thanh khoản và tiến độ các dự án.'),
('VPH_2018_parent', 'VPH', 2018, 'parent', 'Công ty có nhiều giao dịch phức tạp với các bên liên quan, bao gồm cho vay không lãi suất (2 tỷ cho cá nhân), mua bán, đầu tư chéo với các công ty con và liên kết. Một số giao dịch có thể không được thực hiện trên cơ sở thị trường, tiềm ẩn rủi ro xung đột lợi ích và thiếu minh bạch.', 'Nợ vay ngắn hạn chiếm tỷ trọng cao (379,9 tỷ), áp lực trả nợ lớn. Tài sản đảm bảo chủ yếu là quyền sử dụng đất dự án, phụ thuộc vào tiến độ triển khai và tiêu thụ dự án. Công ty dựa vào nguồn vay ngắn hạn để tài trợ hoạt động, tạo rủi ro thanh khoản.', 'Hàng tồn kho lớn (504 tỷ), chủ yếu là chi phí sản xuất kinh doanh dở dang (492 tỷ) cho các dự án bất động sản. Thị trường bất động sản chậm lại có thể dẫn đến ứ đọng vốn, tăng dự phòng giảm giá.', 7, 'Công ty đạt lợi nhuận sau thuế 164 tỷ, doanh thu giảm so với năm trước. Tuy nhiên, nợ vay ngắn hạn cao, áp lực thanh toán lớn. Hàng tồn kho bất động sản dở dang chiếm tỷ trọng lớn, phụ thuộc vào thị trường. Giao dịch bên liên quan phức tạp, tiềm ẩn rủi ro quản trị. Triển vọng phụ thuộc vào khả năng tiêu thụ dự án và quản lý dòng tiền.'),
('VPH_2017_consolidated', 'VPH', 2017, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan bao gồm cho vay, tạm ứng và chuyển nhượng cổ phần. Các giao dịch này được thực hiện theo điều kiện thị trường, tuy nhiên số lượng lớn giao dịch với ban lãnh đạo và công ty liên kết có thể tiềm ẩn rủi ro về xung đột lợi ích.', 'Nợ vay của công ty khá lớn, với tổng nợ ngắn hạn 290.503.452.363 VNĐ và nợ dài hạn 181.954.165.933 VNĐ. Công ty có tài sản thế chấp như quyền sử dụng đất và tài sản hình thành trong tương lai, nhưng áp lực trả nợ lãi vay cao (19.108.688.382 VNĐ trong năm) có thể ảnh hưởng đến dòng tiền.', 'Hàng tồn kho bao gồm chi phí sản xuất kinh doanh dở dang với giá trị lớn (807.454.907.643 VNĐ) và dự phòng giảm giá 22.071.097.153 VNĐ. Các dự án bất động sản dở dang có thể bị ứ đọng nếu thị trường chậm lại, tuy nhiên công ty đã lập dự phòng cho một số dự án.', 6, 'Tình hình tài chính hợp nhất: doanh thu tăng mạnh từ 429 tỷ VNĐ lên 1.382 tỷ VNĐ, lợi nhuận sau thuế đạt 190 tỷ VNĐ. Công ty mở rộng quy mô qua mua lại công ty con, nhưng nợ vay tăng và tồn kho dở dang lớn. Quản trị có nhiều giao dịch với bên liên quan, cần giám sát chặt. Triển vọng trung bình, phụ thuộc vào khả năng tiêu thụ bất động sản và quản lý nợ.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VPH_2017_parent', 'VPH', 2017, 'parent', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, bao gồm cho vay không lãi suất (cho mượn tiền), các giao dịch tạm ứng lớn với thành viên quản lý và giao dịch mua bán, đầu tư với các công ty con, công ty liên kết. Mặc dù các giao dịch được công bố, nhưng khối lượng và tần suất cao làm tăng rủi ro về xung đột lợi ích và quản trị công ty.', 'Công ty có nợ vay lớn, bao gồm nợ ngắn hạn và dài hạn, phần lớn là nợ ngân hàng với lãi suất cao (trên 10%/năm) và nợ từ các cá nhân/tổ chức liên quan. Nợ vay được đảm bảo bằng quyền sử dụng đất và tài sản hình thành trong tương lai từ các dự án. Áp lực trả nợ là đáng kể, đặc biệt với các khoản nợ đến hạn ngắn hạn.', 'Tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang của các dự án bất động sản. Dự án Phú Xuân 2 đã trích lập dự phòng giảm giá 22 tỷ đồng. Các dự án khác chưa trích lập dự phòng, nhưng với đặc thù ngành bất động sản, rủi ro ứ đọng và thanh khoản chậm là hiện hữu nếu thị trường suy giảm.', 7, 'Công ty có kết quả kinh doanh tăng trưởng mạnh trong năm 2017, lợi nhuận sau thuế đạt 190 tỷ đồng. Tuy nhiên, cấu trúc tài chính có nhiều rủi ro: nợ vay lớn và tập trung, nhiều giao dịch phức tạp với các bên liên quan, hàng tồn kho (dự án) chiếm tỷ trọng cao. Quản trị công ty ở mức rủi ro trung bình cao do giao dịch nội bộ và cơ cấu nợ. Triển vọng phụ thuộc vào khả năng tiêu thụ sản phẩm và quản lý dòng tiền từ các dự án.'),
('VPG_2025_consolidated', 'VPG', 2025, 'consolidated', 'Rủi ro trung bình. Công ty có giao dịch với Công ty Cổ phần Xây dựng Bất động sản Việt Phát (cùng chủ sở hữu) với khoản phải trả 16,13 tỷ VND và khoản đầu tư đã thoái vốn trong năm 2025. Kiểm toán viên đã đưa ra ý kiến ngoại trừ liên quan đến khoản trả trước 960,2 tỷ VND cho hai nhà cung cấp (Tất Thành và Âu Việt) - đây là các đối tác chiến lược nhưng không thuộc bên liên quan được công bố. Rủi ro chính nằm ở khả năng thu hồi khoản trả trước lớn, một phần do thị trường than cốc/quặng sắt biến động mạnh.', 'Rủi ro nợ vay cao. Tổng nợ vay ngắn hạn 1.675 tỷ VND và dài hạn 161 tỷ VND. Công ty đã giảm mạnh nợ vay so với đầu năm (từ 4.608 tỷ xuống 1.836 tỷ) bằng nguồn tiền thu từ thoái vốn tài sản (506 tỷ), thu hồi đầu tư (33,5 tỷ) và hoạt động kinh doanh. Nhiều khoản vay được đảm bảo bằng tiền gửi, trái phiếu Agribank, quyền sử dụng đất và hàng tồn kho. Các khoản vay có lãi suất thả nổi từ 5,5% đến 7,7%/năm. Dù đã giảm nợ đáng kể, áp lực trả nợ vẫn cao do tiền mặt chỉ còn 123,7 tỷ VND.', 'Rủi ro tồn kho cao. Hàng tồn kho giảm mạnh từ 3.357 tỷ xuống 407 tỷ VND do Công ty đã chủ động giảm quy mô dự trữ. Tuy nhiên, Công ty phải trích lập dự phòng 256,2 tỷ VND cho lô hàng than nhiệt gửi bán cho PVPBG do chất lượng không đạt tiêu chuẩn hợp đồng. Dự án xây dựng dở dang còn 6,5 tỷ (văn phòng An Biên) dự kiến triển khai 2026.', 8, 'Doanh nghiệp trong tình trạng tài chính nghiêm trọng năm 2025: lợi nhuận sau thuế âm 597 tỷ VND (giảm 648,68% so với cùng kỳ), kiểm toán viên đưa ý kiến ngoại trừ về khoản trả trước 960,2 tỷ VND không rõ khả năng thu hồi. Nguyên nhân chính là doanh thu than nhiệt giảm 30,5%, trích lập dự phòng lớn cho hàng tồn kho và phải thu khó đòi. Ban lãnh đạo cũ (Chủ tịch Nguyễn Văn Bình và TGĐ Nguyễn Văn Đức) bị khởi tố hình sự tội đưa hối lộ, gây bất ổn quản trị. Dù Công ty đã cắt giảm mạnh quy mô hoạt động, giảm nợ vay và thoái vốn tài sản, triển vọng đầu tư vẫn rất rủi ro do phụ thuộc vào việc thu hồi khoản trả trước lớn và ổn định lại hoạt động kinh doanh.'),
('VPG_2025_parent', 'VPG', 2025, 'parent', 'Giao dịch với bên liên quan chủ yếu là đầu tư vào công ty con và công ty liên kết, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay ngắn hạn và dài hạn từ nhiều ngân hàng, với tài sản thế chấp đa dạng. Áp lực nợ vay cao nhưng công ty đã chủ động giảm quy mô nợ để giảm chi phí tài chính.', 'Tồn kho có dự phòng giảm giá lớn đối với hàng than nhiệt gửi bán do chất lượng không đảm bảo và tranh chấp hợp đồng, rủi ro thu hồi cao.', 8, 'Công ty gặp khó khăn nghiêm trọng trong năm 2025 với lỗ sau thuế lớn, doanh thu giảm mạnh do mất hợp đồng cung cấp than, trích lập dự phòng tồn kho và phải thu khó đòi. Triển vọng phụ thuộc vào việc giải quyết tranh chấp hợp đồng và cải thiện quản trị.'),
('VPG_2024_parent', 'VPG', 2024, 'parent', 'Công ty có giao dịch đáng kể với các bên liên quan: đầu tư 270 tỷ VND vào công ty con Newland, đầu tư và nhận lại vốn 114.27 tỷ VND từ Công ty CP Xây dựng BĐS Việt Phát (cùng chủ sở hữu). Cổ đông lớn/ban lãnh đạo (ông Nguyễn Văn Bình, ông Nguyễn Văn Đức) đứng ra bảo lãnh cá nhân cho các khoản vay ngân hàng, cho thấy sự gắn kết tài chính cao giữa công ty và cổ đông. Tổng thù lao ban lãnh đạo 3.27 tỷ VND/năm là hợp lý so với quy mô doanh nghiệp. Chưa phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay rất cao: tổng nợ phải trả 6,642 tỷ VND chiếm 81.8% tổng tài sản. Nợ ngắn hạn 4,354 tỷ VND lớn hơn nhiều so với tiền mặt 1,614 tỷ VND. Công ty phụ thuộc lớn vào các khoản vay UPAS LC (thư tín dụng trả chậm) để tài trợ hoạt động thương mại. Nhiều khoản vay lãi suất cao (6.2-6.5%/năm tại VPBank). Tài sản thế chấp bao gồm quyền sử dụng đất, trái phiếu, tiền gửi và phải thu khách hàng. Nợ dài hạn 176.3 tỷ VND tại Agribank được đảm bảo bằng bất động sản đầu tư và chi phí xây dựng dở dang.', 'Hàng tồn kho lớn 2,968 tỷ VND (tăng 15% so với đầu năm), trong đó hàng gửi đi bán chiếm 1,561 tỷ VND và hàng hóa 1,362 tỷ VND. Hàng tồn kho chủ yếu là than cốc, than nhiệt và quặng sắt - hàng hóa có biến động giá lớn. Chi phí xây dựng dở dang giảm mạnh từ 482.5 tỷ xuống 75.9 tỷ VND do hoàn thành chuyển giao bất động sản đầu tư Tòa nhà 2 Trần Hưng Đạo. Một số hàng hóa đã được dùng để đảm bảo cho vay ngân hàng.', 6, 'Công ty VPG có quy mô doanh thu lớn (15,690 tỷ VND năm 2024, tăng 148% so với năm trước) nhưng biên lợi nhuận gộp rất thấp chỉ 2.86%, cho thấy hoạt động thương mại hàng hóa (than, quặng sắt) có biên mỏng. Lợi nhuận sau thuế giảm 58.68% so với năm trước do lỗ gộp mặt hàng than cốc và than nhiệt giảm. Công ty bị truy thu thuế lớn theo quyết định xử phạt hành chính, ảnh hưởng tiêu cực đến lợi nhuận. Nợ vay chiếm tỷ trọng cao trong cơ cấu tài chính, tạo áp lực chi phí tài chính 313 tỷ VND/năm. Tuy nhiên, công ty có hệ thống khách hàng lớn (nhiệt điện, thép) và đang mở rộng sang kinh doanh bất động sản đầu tư cho thuê. Triển vọng phụ thuộc vào khả năng kiểm soát biên lợi nhuận thương mại và quản lý dòng tiền trong bối cảnh nợ vay cao.'),
('VPG_2024_consolidated', 'VPG', 2024, 'consolidated', 'Công ty có giao dịch với bên liên quan là Công ty Cổ phần Xây dựng Bất động sản Việt Phát (cùng chủ sở hữu), bao gồm nhận lại tiền góp vốn và mua hàng hóa/dịch vụ với giá trị lớn. Tuy nhiên, chưa thấy bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay ngắn hạn và dài hạn lớn, tập trung vào các ngân hàng thương mại lớn. Các khoản vay được đảm bảo bằng tài sản cố định, quyền sử dụng đất và hàng tồn kho. Lãi suất dao động từ 3.8% đến 11.5%/năm. Áp lực trả nợ cao do nợ ngắn hạn chiếm tỷ trọng lớn, nhưng khả năng thanh toán được hỗ trợ bởi dòng tiền từ hoạt động kinh doanh và tài sản thế chấp.', 'Hàng tồn kho chủ yếu là hàng hóa và bất động sản dở dang (Dự án Royal River City). Dự án bất động sản đang trong quá trình xây dựng và bán, có thể bị ảnh hưởng bởi biến động thị trường. Hàng tồn kho khác bao gồm nguyên liệu và thành phẩm, không có dự phòng giảm giá.', 5, 'Công ty tăng trưởng doanh thu mạnh (156.51%) trong năm 2024, chủ yếu từ kinh doanh bất động sản và khoáng sản. Tuy nhiên, biên lợi nhuận gộp thấp (3.92%) cho thấy áp lực chi phí. Nợ vay cao, tập trung vào mục đích bổ sung vốn lưu động, tiềm ẩn rủi ro lãi suất và thanh khoản. Công ty có giao dịch với bên liên quan ở mức độ vừa phải. Điểm rủi ro quản trị trung bình. Triển vọng phụ thuộc vào khả năng tiêu thụ bất động sản và quản lý chuỗi cung ứng khoáng sản.'),
('VPG_2023_parent', 'VPG', 2023, 'parent', 'Công ty có giao dịch với các bên liên quan bao gồm cổ đông lớn, chủ tịch HĐQT, tổng giám đốc và phó tổng giám đốc. Năm 2023, chỉ phát sinh giao dịch chia cổ tức, nhưng năm 2022 có các khoản tạm ứng lớn cho cá nhân (hơn 2,000 tỷ VND) và ứng trước cho nhà cung cấp là công ty cùng người quản lý chủ chốt. Điều này cho thấy rủi ro về giao dịch không minh bạch và tiềm ẩn lợi ích cá nhân.', 'Công ty có áp lực nợ vay lớn với tổng nợ ngắn hạn hơn 5.178 tỷ VND và nợ dài hạn 191 tỷ VND. Nợ chủ yếu từ nhiều ngân hàng với lãi suất biến động (từ 3.3% đến 8.5%/năm) và được đảm bảo bằng tài sản thế chấp (đất, nhà, trái phiếu, hàng tồn kho). Việc tài trợ vốn lưu động dựa vào nợ ngắn hạn và UPAS LC làm tăng rủi ro thanh khoản và chi phí tài chính tăng mạnh 68.72% trong năm.', 'Tồn kho tăng mạnh từ 1,544 tỷ VND lên 2,579 tỷ VND, chủ yếu là hàng hóa (than, quặng sắt) với giá trị lớn. Hàng tồn kho dễ bị ảnh hưởng bởi biến động giá nguyên liệu và rủi ro tồn kho lỗi thời. Công ty cũng dùng hàng tồn kho để đảm bảo cho vay, tạo áp lực tài chính.', 7, 'Công ty tăng trưởng doanh thu 14.46% nhưng lợi nhuận sau thuế giảm 67.75% do chi phí tài chính tăng cao và thu nhập khác giảm. Cơ cấu tài chính phụ thuộc lớn vào nợ vay, với tỷ lệ nợ/vốn chủ sở hữu cao (3.67 lần). Dòng tiền từ hoạt động kinh doanh âm (-216.5 tỷ VND) cho thấy áp lực thanh toán. Triển vọng phụ thuộc vào khả năng kiểm soát chi phí, quản lý tồn kho và giảm rủi ro giao dịch liên quan.'),
('VPG_2023_consolidated', 'VPG', 2023, 'consolidated', 'Công ty có giao dịch đáng kể với Công ty Cổ phần Xây dựng Bất động sản Việt Phát (cùng chủ sở hữu) bao gồm mua hàng hóa 33,6 tỷ VND, trả trước 96,6 tỷ VND và đầu tư góp vốn 147,75 tỷ VND. Ngoài ra, năm 2022 có các khoản tạm ứng lớn cho cổ đông lớn/Chủ tịch HĐQT (1.200 tỷ VND cho ông Nguyễn Văn Bình, 911,7 tỷ VND cho ông Nguyễn Văn Đức) đã được thu hồi trong năm. Thù lao ban lãnh đạo ở mức hợp lý (tổng 2,82 tỷ VND). Các giao dịch không có dấu hiệu bất thường rõ ràng về giá hay điều kiện, tuy nhiên quy mô trả trước cho bên liên quan (96,6 tỷ VND) cần được theo dõi.', 'Tổng nợ vay ngắn hạn và dài hạn khoảng 2.219 tỷ VND, trong khi vốn chủ sở hữu chỉ 1.493 tỷ VND, tỷ lệ nợ/vốn chủ sở hữu xấp xỉ 1,49 lần. Chi phí tài chính tăng mạnh 68,72% (251,2 tỷ VND) do tăng vay để phục vụ kinh doanh than nhiệt. Các khoản UPAS LC phải trả lên đến 2.324 tỷ VND là nghĩa vụ tín dụng quan trọng. Nhiều khoản vay được đảm bảo bằng tiền gửi, TSCĐ, quyền sử dụng đất và hàng tồn kho, cho thấy mức độ thế chấp cao. Dự án 80 Hạ Lý vay với lãi suất cao 11,5-14%/năm tạo áp lực tài chính đáng kể.', 'Hàng tồn kho cuối năm 2.994 tỷ VND tăng 59% so với đầu năm (1.880 tỷ VND), chủ yếu do tăng hàng hóa (than, quặng sắt). Dự án 80 Hạ Lý (415,4 tỷ VND) đang trong quá trình xây dựng với cam kết hợp đồng 270 tỷ VND chưa hoàn thành, dự án này đã được thế chấp cho khoản vay dài hạn. Rủi ro tồn kho ở mức trung bình do hàng hóa chủ yếu là nguyên liệu thương mại có tính thanh khoản, nhưng quy mô tăng nhanh cần được giám sát.', 6, 'Công ty VPG hoạt động chính trong kinh doanh khoáng sản (than, quặng sắt, thép) với biên lợi nhuận gộp mỏng 6,1%. Lợi nhuận sau thuế năm 2023 đạt 19,4 tỷ VND, giảm 69% so với năm trước do chi phí tài chính tăng mạnh 68,72% (do tăng sản lượng than nhiệt cần huy động vốn) và thu nhập khác giảm 81,48%. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Rủi ro chính bao gồm: (1) đòn bẩy tài chính cao với tổng nợ vay vượt vốn chủ sở hữu, (2) chi phí tài chính tăng nhanh ảnh hưởng lợi nhuận, (3) quy mô hàng tồn kho tăng mạnh, (4) đầu tư vào dự án bất động sản (80 Hạ Lý) với vốn lớn và lãi suất vay cao. Triển vọng phụ thuộc vào diễn biến giá nguyên liệu và khả năng quản lý dòng tiền từ hoạt động kinh doanh thương mại.'),
('VPG_2022_consolidated', 'VPG', 2022, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các bên liên quan, bao gồm cho vay không lãi suất cho cổ đông lớn và mua bán hàng hóa. Điều này có thể dẫn đến rủi ro về xung đột lợi ích và quản trị công ty.', 'Áp lực nợ vay lớn, nợ ngắn hạn và dài hạn đều tăng mạnh. Lãi suất vay từ 6.5% đến 14%/năm, và tài sản thế chấp bao gồm hàng tồn kho và bất động sản, cho thấy rủi ro thanh khoản.', 'Hàng tồn kho dở dang, đặc biệt là dự án bất động sản, có thể bị ứ đọng nếu thị trường bất động sản chậm lại. Giá trị hàng tồn kho tăng mạnh so với năm trước.', 7, 'Doanh nghiệp có tăng trưởng doanh thu mạnh nhưng lợi nhuận giảm đáng kể do chi phí tài chính tăng. Nợ vay tăng nhanh và giao dịch với các bên liên quan频繁 đòi hỏi giám sát chặt chẽ.'),
('VPD_2024_consolidated', 'VPD', 2024, 'consolidated', 'Công ty có sự phụ thuộc lớn vào Tập đoàn Điện lực Việt Nam (doanh thu bán điện chiếm khoảng 97% tổng doanh thu năm 2024). Giao dịch với các bên liên quan chủ yếu là mua bán hàng hóa và dịch vụ trong hệ thống điện lực, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường. Tuy nhiên, rủi ro tập trung khách hàng cao.', 'Nợ vay chủ yếu là vay đầu tư Dự án Nhà máy Thủy điện Khe Bố, được thế chấp bằng tài sản dự án. Công ty có dòng tiền hoạt động kinh doanh mạnh (471 tỷ VNĐ năm 2024), giảm nợ vay ngắn hạn đáng kể (từ 89 tỷ xuống 59 tỷ VNĐ). Áp lực nợ vay ở mức kiểm soát được.', 'Hàng tồn kho giá trị thấp (6,7 tỷ VNĐ), chủ yếu là nguyên vật liệu và công cụ dụng cụ, không có rủi ro ứ đọng lớn. Dự án xây dựng dở dang trị giá 3,8 tỷ VNĐ, liên quan đến sửa chữa và gia cố, không phải dự án lớn mới.', 4, 'Công ty Cổ phần Phát triển Điện lực Việt Nam (VPD) hoạt động trong lĩnh vực sản xuất điện năng, chủ yếu là thủy điện. Năm 2024, doanh thu tăng 9,42% nhờ sản lượng điện tăng, lợi nhuận sau thuế tăng 11,41%. Công ty có dòng tiền hoạt động mạnh, giảm đáng kể nợ vay ngắn hạn và tăng tiền mặt tương đương tiền. Tuy nhiên, doanh thu phụ thuộc lớn vào Tập đoàn Điện lực Việt Nam. Nợ vay được đảm bảo bằng tài sản dự án và dòng tiền ổn định. Công ty duy trì mức cổ tức cao. Triển vọng tích cực trong trung hạn, nhưng cần theo dõi rủi ro thủy văn và giá điện.'),
('VPG_2022_parent', 'VPG', 2022, 'parent', 'Công ty có nhiều giao dịch lớn với các bên liên quan, bao gồm tạm ứng và đầu tư vào công ty con, có thể gây rủi ro về quản trị và xung đột lợi ích. Ví dụ, tạm ứng hàng nghìn tỷ cho Chủ tịch và Tổng Giám đốc.', 'Nợ vay ngắn hạn và dài hạn tổng cộng trên 1.400 tỷ VND, với lãi suất cao lên đến 11,5%/năm. Tài sản thế chấp bao gồm bất động sản và tiền gửi, gây áp lực lên dòng tiền và khả năng thanh toán.', 'Hàng tồn kho tăng mạnh từ 727 tỷ lên 1.544 tỷ VND, bao gồm hàng hóa đang vận chuyển và chi phí xây dựng dở dang, có nguy cơ ứ đọng và giảm giá.', 7, 'Sức khỏe tài chính của công ty bị suy giảm do lợi nhuận giảm mạnh 85% so với năm trước, nợ vay tăng cao, và rủi ro từ giao dịch bên liên quan. Triển vọng đầu tư cần thận trọng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VPD_2023_consolidated', 'VPD', 2023, 'consolidated', 'Rủi ro cao. Doanh thu bán điện (chiếm >98% doanh thu) phụ thuộc chủ yếu vào Tập đoàn Điện lực Việt Nam và Tổng Công ty Điện lực Miền Bắc. Giao dịch tập trung lớn, có thể ảnh hưởng đến tính độc lập trong đàm phán giá và điều kiện thanh toán.', 'Rủi ro trung bình. Nợ vay giảm mạnh từ 380 tỷ xuống 168 tỷ, chủ yếu là nợ dài hạn (78.7 tỷ). Lãi suất vay ưu đãi (từ 6.4%-9.2%/năm) và được chuyển đổi sang BIDV. Tài sản thế chấp chủ yếu là toàn bộ tài sản dự án Nhà máy Thủy điện Khe Bố.', 'Rủi ro thấp. Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ dụng cụ, không có dự phòng giảm giá. Chi phí xây dựng dở dang chỉ 2.5 tỷ, tập trung vào sửa chữa gia cố hạ lưu nhà máy, không có dự án treo lớn.', 6, 'Sức khỏe tài chính ổn định với lợi nhuận sau thuế 190.5 tỷ dù giảm so với năm trước. Nợ vay giảm mạnh nhờ tái cấu trúc, thanh khoản tốt. Rủi ro lớn nhất là phụ thuộc vào thủy văn và khách hàng chính (EVN). Công ty trả cổ tức cao (138.5 tỷ) và duy trì quỹ đầu tư phát triển lớn (62.6 tỷ) cho tăng trưởng.'),
('VPD_2025_consolidated', 'VPD', 2025, 'consolidated', 'Doanh thu bán điện của Công ty phụ thuộc gần như hoàn toàn (trên 99%) vào Tập đoàn Điện lực Việt Nam (EVN) và Tổng Công ty Điện lực miền Bắc (EVNNPC) - đây là đặc thù ngành điện tại Việt Nam khi EVN là đơn vị mua điện duy nhất. Giá bán điện tuân theo quy định tại Thông tư số 12/2025/TT-BCT. Tuy nhiên, hợp đồng mua bán điện Nhà máy Thủy điện Nậm Má với EVNNPC đã hết hạn ngày 22/05/2024 và hai bên đang đàm phán hợp đồng mới, tạo rủi ro về giá và thời gian ký kết. Các giao dịch mua hàng với các bên liên quan (công ty con/cháu của EVN) có giá trị nhỏ và tuân theo giá thị trường, không có dấu hiệu giao dịch bất thường hay chuyển giá.', 'Công ty đã giảm mạnh nợ vay từ 78,76 tỷ VND xuống còn 20 tỷ VND trong năm 2025, phản ánh khả năng trả nợ tốt. Chỉ còn một khoản vay duy nhất từ BIDV đáo hạn năm 2026 với lãi suất thả nổi. Với vị thế tiền mặt lớn (280,6 tỷ VND) và dòng tiền hoạt động kinh doanh dương mạnh (299,1 tỷ VND), áp lực nợ vay rất thấp. Các khoản vay được bảo đảm bằng tài sản thế chấp đã đăng ký đầy đủ.', 'Hàng tồn kho ở mức thấp (5,6 tỷ VND), chủ yếu là nguyên vật liệu và công cụ dụng cụ phục vụ sản xuất điện, không có dự phòng giảm giá. Chi phí XDCB dở dang tăng từ 3,8 tỷ lên 13,3 tỷ VND do đầu tư nâng cấp hệ thống điều khiển tại Nhà máy Thủy điện Bắc Bình, phản ánh hoạt động đầu tư phát triển bình thường, không có dấu hiệu ứ đọng hay lãng phí.', 3, 'Công ty Cổ phần Phát triển Điện lực Việt Nam (VPD) có kết quả kinh doanh tích cực năm 2025 với lợi nhuận sau thuế đạt 262,4 tỷ VND, tăng 23,6% so với năm 2024 nhờ thủy văn thuận lợi làm sản lượng điện tăng mạnh. Tỷ suất lợi nhuận gộp đạt 55,6%, phản ánh biên lợi nhuận cao đặc thù của ngành thủy điện. Cơ cấu tài chính lành mạnh với tỷ lệ nợ vay/vốn chủ sở hữu rất thấp (1,2%), tiền mặt dồi dào (280,6 tỷ VND). Công ty duy trì chi trả cổ tức đều đặn (tỷ lệ 16% năm 2024). Rủi ro chính là phụ thuộc hoàn toàn vào EVN trong việc tiêu thụ điện và hợp đồng mua bán điện mới với EVNNPC chưa được ký kết. Ban lãnh đạo có sự thay đổi trong năm (Tổng Giám đốc mới từ 25/04/2025) nhưng không tạo ra bất ổn lớn. Triển vọng ngắn hạn tích cực, dài hạn phụ thuộc vào thủy văn và tiến độ ký hợp đồng điện mới.'),
('VPD_2021_consolidated', 'VPD', 2021, 'consolidated', 'Công ty có giao dịch lớn với các bên liên quan trong Tập đoàn Điện lực Việt Nam, cụ thể Công ty Mua bán điện chiếm tỷ trọng doanh thu bán điện lớn (553 tỷ VND/566 tỷ VND doanh thu bán điện, tương đương 97,7%). Tuy nhiên, đây là đặc thù ngành điện khi sản lượng điện phải bán cho đơn vị phân phối trong Tập đoàn EVN. Các giao dịch thù lao HĐQT và ban lãnh đạo ở mức hợp lý, không có dấu hiệu giao dịch bất thường hay lợi ích nhóm đáng ngờ.', 'Tổng nợ vay 609,6 tỷ VND, giảm mạnh so với đầu năm 800,2 tỷ VND nhờ trả nợ gốc 191,7 tỷ VND trong năm. Áp lực nợ ngắn hạn cao (231 tỷ VND vay dài hạn đến hạn trả). Công ty có trái phiếu đáo hạn trong năm 2022. Tuy nhiên, dòng tiền hoạt động kinh doanh mạnh (349,5 tỷ VND) và tiền gửi ngân hàng dồi dào (113,4 tỷ VND) giúp Công ty có khả năng thanh toán nợ. Tài sản thế chấp lớn (TSCĐ hữu hình 1.829 tỷ VND, TSCĐ vô hình 4,9 tỷ VND).', 'Hàng tồn kho ở mức rất thấp (1,2 tỷ VND) so với tổng tài sản, chủ yếu là nguyên liệu và sản phẩm dở dang của Trung tâm Tư vấn. Chi phí xây dựng cơ bản dở dang giảm mạnh từ 880 triệu xuống 251 triệu VND, không có dấu hiệu ứ đọng. Dự án thủy điện Khe Bố đã đi vào hoạt động ổn định.', 7, 'Công ty Thủy điện có kết quả kinh doanh xuất sắc năm 2021 với doanh thu tăng 25% và lợi nhuận sau thuế tăng 104% nhờ thủy văn thuận lợi. Tỷ suất lợi nhuận gộp cao 52,5%. Dòng tiền hoạt động kinh doanh mạnh 349,5 tỷ VND, giúp giảm nợ vay đáng kể. Điểm rủi ro chính: (1) Phụ thuộc lớn vào Tập đoàn EVN trong tiêu thụ điện; (2) Áp lực trả nợ trái phiếu đáo hạn 2022; (3) Ưu đãi thuế 50% tại Nhà máy Khe Bố có thời hạn. Công ty có tài sản thế chấp lớn, thanh khoản tốt, triển vọng tích cực trong trung hạn.'),
('VPD_2020_consolidated', 'VPD', 2020, 'consolidated', 'Phần lớn doanh thu và phải thu khách hàng của Công ty tập trung vào các bên liên quan thuộc Tập đoàn Điện lực Việt Nam: Công ty Mua bán điện Việt Nam và Tổng Công ty Điện lực Miền Bắc. Doanh thu từ các bên liên quan chiếm 453,7 tỷ VND trên tổng doanh thu 455,2 tỷ VND (~99,7%). Phải thu ngắn hạn từ các bên liên quan chiếm 96,1 tỷ VND trên tổng phải thu khách hàng 96,3 tỷ VND. Mức tập trung khách hàng cực kỳ cao tạo rủi ro phụ thuộc, tuy nhiên đây là đặc thù của ngành điện lực Việt Nam với EVN là bên mua điện duy nhất. Các giao dịch theo giá quy định của ngành, không phát hiện dấu hiệu giao dịch bất thường (cho vay không lãi suất, mua bán chênh lệch lớn).', 'Tổng nợ phải trả 892,8 tỷ VND, trong đó nợ ngắn hạn 228,1 tỷ và nợ dài hạn 664,6 tỷ. Chi phí lãi vay năm 2020 là 81,5 tỷ VND, chiếm tỷ trọng đáng kể trong lợi nhuận hoạt động (86,4%). Công ty đã phát hành 340 tỷ VND trái phiếu riêng lẻ với lãi suất cao 9,5% cho kỳ đầu. Tài sản cố định hữu hình có giá trị còn lại 1.974 tỷ VND và vô hình 5,1 tỷ VND đã được dùng thế chấp đảm bảo cho các khoản vay. Công ty đã giảm nợ ngắn hạn từ 414,2 tỷ xuống 135,6 tỷ VND trong năm. Dòng tiền hoạt động kinh doanh dương 188,2 tỷ VND đảm bảo khả năng thanh toán lãi vay. Tuy nhiên, cơ cấu nợ dài hạn lớn với nhiều khoản đáo hạn 2022-2026 tạo áp lực tái tài trợ.', 'Hàng tồn kho giảm nhẹ từ 1,19 tỷ xuống 1,01 tỷ VND, mức thấp và không đáng lo ngại. Chi phí xây dựng cơ bản dở dang tăng từ 93 triệu lên 880,7 triệu VND do mua sắm tài sản cố định. Điểm đáng lưu ý là dự án Nhà máy Thủy điện Khe Bố còn nhiều chi phí bồi thường GPMB, di dân tái định cư đã hoàn thành nhưng chưa nghiệm thu quyết toán (chi phí trích trước 12,8 tỷ VND). Dự án Nhà máy Thủy điện Nậm Má tại Hà Giang đang trong giai đoạn triển khai. Nhìn chung, rủi ro tồn kho ở mức thấp do hoạt động chính là sản xuất điện không đòi hỏi hàng tồn kho lớn.', 4, 'Công ty CP Phát triển Điện lực Việt Nam (VNPD) là doanh nghiệp sản xuất và phân phối điện với 3 nhà máy thủy điện (Khe Bố, Bắc Bình, Nậm Má) và 1 trung tâm tư vấn. Kết quả kinh doanh năm 2020 giảm 16,9% so với năm trước do ảnh hưởng Covid-19 khiến nhu cầu điện giảm, các nhà máy phải chạy phát điện vào giờ thấp điểm làm giá bán trung bình giảm 7%. Tuy nhiên, biên lợi nhuận gộp vẫn đạt 45% cho thấy hiệu quả sản xuất kinh doanh cơ bản tốt. Công ty có tỷ lệ nợ phải trả/vốn chủ sở hữu ~0,7, đã chủ động giảm nợ ngắn hạn mạnh từ 414 tỷ xuống 135,6 tỷ VND. Mối quan hệ mật thiết với Tập đoàn Điện lực Việt Nam đảm bảo đầu ra ổn định nhưng tạo sự phụ thuộc lớn vào một nhóm khách hàng. Công ty duy trì chi trả cổ tức đều đặn (500 VND/cổ phiếu năm 2020). Đánh giá: Sức khỏe tài chính trung bình khá, triển vọng phụ thuộc lớn vào thủy văn và chính sách giá điện.'),
('VPD_2015_consolidated', 'VPD', 2015, 'consolidated', 'Công ty có giao dịch doanh thu bán hàng lớn với các công ty cùng Tập đoàn Điện lực Việt Nam (Công ty Mua bán điện Việt Nam, Tổng Công ty Điện lực Miền Bắc). Các giao dịch này là nghiệp vụ kinh doanh bình thường trong ngành, chưa phát hiện dấu hiệu bất thường như mua bán chênh lệch lớn hay cho vay không lãi suất.', 'Áp lực nợ vay rất lớn với tổng nợ phải trả là 1,774,021,646,236 VND, chiếm tỷ trọng cao trong tổng nguồn vốn. Nợ vay ngắn hạn và dài hạn đều cao, chi phí lãi vay năm 2015 là 136,158,220,358 VND. Tài sản cố định (giá trị còn lại 2.705 tỷ VND) được dùng để thế chấp cho các khoản vay, cho thấy doanh nghiệp đang tận dụng tối đa tài sản để vay vốn, tiềm ẩn rủi ro thanh khoản nếu dòng tiền kinh doanh suy giảm.', 'Hàng tồn kho ở mức thấp (2.26 tỷ VND), chủ yếu là nguyên vật liệu và công cụ dụng cụ phục vụ sản xuất điện, không có hàng thành phẩm tồn kho lớn. Dự án Sông Bạc trong tài sản dở dang có giá trị 636 triệu VND đang chờ thanh toán từ chủ đầu tư mới, tuy nhiên đây là khoản chi phí đã được ghi nhận từ các năm trước và không tạo áp lực tồn kho lớn.', 5, 'Công ty là doanh nghiệp sản xuất điện, chịu ảnh hưởng lớn từ điều kiện thời tiết (hạn hán năm 2015). Kết quả kinh doanh sụt giảm mạnh, lợi nhuận sau thuế giảm từ 71.4 tỷ xuống 43.3 tỷ VND. Nợ vay lớn, tập trung vào các khoản vay dài hạn được thế chấp bằng tài sản cố định là các nhà máy thủy điện. Công ty được hưởng ưu đãi thuế lớn từ hai nhà máy, giúp giảm đáng kể chi phí thuế. Dòng tiền từ hoạt động kinh doanh vẫn dương nhưng giảm so với năm trước. Rủi ro chính là sự phụ thuộc vào thời tiết và đòn bẩy tài chính cao.'),
('VPD_2017_consolidated', 'VPD', 2017, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là doanh thu bán hàng và cổ tức trong Tập đoàn Điện lực Việt Nam, không có dấu hiệu bất thường như cho vay không lãi suất hay chênh lệch giá lớn.', 'Áp lực nợ vay cao với lãi suất từ 6.90% đến 10.54%, nợ được đảm bảo bằng tài sản cố định. Tuy nhiên, lợi nhuận năm 2017 tăng mạnh nên khả năng thanh toán cải thiện.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và dự án dở dang, không có dấu hiệu ứ đọng hay giảm giá trị trọng yếu. Các dự án xây dựng dở dang đang triển khai bình thường.', 5, 'Công ty có kết quả kinh doanh tích cực năm 2017 với lợi nhuận trước thuế tăng 228% nhờ sản lượng điện tăng. Nợ vay lớn và lãi suất cao là rủi ro chính, nhưng dòng tiền kinh doanh mạnh. Triển vọng phụ thuộc vào điều kiện thủy văn và chính sách giá điện của Nhà nước.'),
('VPB_2025_consolidated', 'VPB', 2025, 'consolidated', 'Giao dịch với SMBC (cổ đông lớn) chiếm tỷ trọng lớn: số dư vay từ SMBC đạt 49.859 tỷ đồng (chiếm khoảng 4,6% tổng nợ phải trả), tiền gửi tại SMBC đạt 11.451 tỷ đồng. Giao dịch phái sinh với SMBC có giá trị hợp đồng 21.417 tỷ đồng. Chi phí lãi vay SMBC năm 2025 là 2.002 tỷ đồng, tăng mạnh so với 753 tỷ đồng năm 2024. Ngoài ra, VPBank cho vay Công ty Eurowindow 322 tỷ đồng (ông Nguyễn Đức Vinh - Tổng Giám đốc là thành viên HĐQT Eurowindow). Các giao dịch với thành viên HĐQT, BKS, Ban TGD: tiền gửi có kỳ hạn và giấy tờ có giá 310 tỷ đồng. Nhìn chung, giao dịch bên liên quan có quy mô đáng kể nhưng được công khai trong thuyết minh.', 'Tổng nợ phải trả 1.079.874 tỷ đồng, tăng 39% so với năm trước. Nợ vay từ TCTC/TCTD khác tăng mạnh từ 89.893 tỷ lên 154.421 tỷ đồng (tăng 72%). Tiền gửi khách hàng tăng 29% lên 628.045 tỷ đồng. Phát hành giấy tờ có giá tăng 60% lên 107.121 tỷ đồng, bao gồm trái phiếu quốc tế 300 triệu USD kỳ hạn 5 năm. Vốn chủ sở hữu đạt 180.276 tỷ đồng, tỷ lệ an toàn vốn (CAR) cần được đánh giá. Ngân hàng có nghĩa vụ tiềm tàng và cam kết đưa ra 1.050.493 tỷ đồng, tăng 52%. Áp lực nợ vay đáng kể do tăng trưởng tín dụng mạnh (tăng 37% cho vay khách hàng).', 'Ngân hàng không có hàng tồn kho truyền thống. Rủi ro chính nằm ở chất lượng tín dụng: nợ có khả năng mất vốn (nhóm 5) tăng 50% từ 6.119 tỷ lên 9.155 tỷ đồng. Nợ dưới tiêu chuẩn và nợ nghi ngờ vẫn ở mức cao. Dự phòng rủi ro cho vay đạt 17.429 tỷ đồng. Chi phí dự phòng rủi ro tín dụng năm 2025 là 25.399 tỷ đồng, giảm 9% so với năm trước. Tài sản bảo đảm nhận thay thế (bất động sản) trị giá 568 tỷ đồng đang chờ xử lý cho thấy một phần nợ xấu đã chuyển thành tài sản thực.', 4, 'VPBank có kết quả kinh doanh tích cực năm 2025 với lợi nhuận sau thuế tăng 52% lên 24.355 tỷ đồng, thu nhập lãi thuần tăng 17% lên 58.663 tỷ đồng. Tổng tài sản tăng 36% lên 1.260.150 tỷ đồng. Tuy nhiên, tăng trưởng nhanh đi kèm rủi ro: nợ có khả năng mất vốn tăng 50%, giao dịch bên liên quan với SMBC quy mô lớn, nợ vay tăng mạnh 72%. Ngân hàng đã phát hành trái phiếu quốc tế 300 triệu USD và tăng vốn qua phát hành cổ phiếu 12.619 tỷ đồng. Tỷ lệ nợ xấu trên tổng dư nợ cho vay ở mức khoảng 1,15% (nhóm 3-5). Triển vọng tích cực nhưng cần theo dõi sát chất lượng tài sản và rủi ro tập trung tín dụng vào bất động sản (22% dư nợ).'),
('VPD_2016_consolidated', 'VPD', 2016, 'consolidated', 'Công ty có doanh thu bán hàng chủ yếu từ Công ty Mua bán Điện và Tổng Công ty Điện lực Miền Bắc, đều là công ty cùng Tập đoàn. Giao dịch có thể được thực hiện theo giá thỏa thuận nội bộ, cần kiểm tra tính độc lập.', 'Công ty có nợ vay lớn với lãi suất thay đổi theo thời kỳ, được đảm bảo bằng tài sản. Áp lực trả nợ có thể tăng nếu lãi suất tăng, nhưng dòng tiền từ hoạt động kinh doanh ổn định.', 'Hàng tồn kho chủ yếu là nguyên liệu và chi phí dở dang, không có dự phòng giảm giá, rủi ro thấp.', 5, 'Công ty hoạt động trong lĩnh vực điện lực, có dòng tiền ổn định từ hoạt động kinh doanh. Tuy nhiên, phụ thuộc vào bán hàng nội bộ và nợ vay cao, nhưng có tài sản thế chấp đủ để đảm bảo.'),
('VPB_2025_parent', 'VPB', 2025, 'parent', 'Giao dịch với các bên liên quan chủ yếu là giao dịch ngân hàng thông thường như tiền gửi, cho vay và hợp đồng phái sinh. Không có bằng chứng về giao dịch bất thường hay ưu đãi không công bằng, nhưng mức độ giao dịch cao với công ty con và cổ đông lớn.', 'Áp lực nợ vay cao với tổng nợ phải trả lớn, nhưng ngân hàng có tài sản dồi dào và đa dạng. Lãi suất nợ vay dao động trong khoảng thị trường, và ngân hàng quản lý thanh khoản tốt với dự trữ tại NHNN.', 'Hàng tồn kho và dự án xây dựng dở dang có giá trị không đáng kể, không gây rủi ro tài chính cho ngân hàng.', 5, 'VPBank là ngân hàng thương mại lớn với tăng trưởng mạnh trong năm 2025, lợi nhuận tăng đáng kể. Các rủi ro được quản lý tốt, triển vọng đầu tư tích cực nhờ nguồn thu nhập đa dạng và cơ sở vốn vững chắc.'),
('VPB_2024_parent', 'VPB', 2024, 'parent', 'Giao dịch với các bên liên quan có quy mô lớn và phức tạp. Đặc biệt: (1) VPB SMBC FC (công ty con 50%) có giao dịch tiền gửi có kỳ hạn lên tới 392.305 tỷ VND và mua nợ gốc 5.380 tỷ VND, cho thấy mức độ liên kết tài chính cao giữa ngân hàng mẹ và công ty tài chính con. (2) SMBC là cổ đông lớn (15,005%) với khoản vay từ SMBC lên tới 5.016 tỷ VND và giao dịch phái sinh giá trị danh nghĩa 28.287 tỷ VND, tạo rủi ro tập trung giao dịch. (3) OPES (công ty con 99,13%) nhận tăng vốn 715 tỷ VND và trả cổ tức 218 tỷ VND. (4) Giao dịch với các thành viên HĐQT, Ban KS và Ban TGĐ bao gồm tiền gửi có kỳ hạn 1.650 tỷ VND, cho thấy mối quan hệ tín dụng nội bộ. Tuy nhiên, các giao dịch này đã được công khai đầy đủ trong thuyết minh và được kiểm toán độc lập xác nhận.', 'Áp lực nợ vay ở mức cao. Tổng nợ phải trả là 739.547 tỷ VND, gấp 5,27 lần vốn chủ sở hữu (140.289 tỷ VND). Nợ ngắn hạn chiếm tỷ trọng lớn: tiền gửi khách hàng 485.736 tỷ VND, tiền gửi TCTC/TCTD 111.821 tỷ VND, phát hành giấy tờ có giá 46.596 tỷ VND. Tuy nhiên, ngân hàng duy trì tiền và tương đương tiền ở mức 164.387 tỷ VND. Nợ vay từ SMBC (cổ đông lớn) chiếm tỷ trọng đáng kể với 5.016 tỷ VND. Tỷ lệ dự trữ bắt buộc được duy trì đúng quy định NHNN. Ngân hàng có đa dạng nguồn huy động từ khách hàng cá nhân (62,41%) và doanh nghiệp (37,59%).', 'Ngân hàng không có hàng tồn kho hay dự án xây dựng dở dang theo nghĩa truyền thống. Tuy nhiên, các tài sản liên quan cần lưu ý: (1) Trái phiếu đặc biệt VAMC trị giá 992.927 triệu VND - là công cụ xử lý nợ xấu với lãi suất 0%/năm, kỳ hạn 5 năm, phản ánh nợ xấu đã bán cho VAMC nhưng chưa xử lý dứt điểm. (2) Chứng khoán đầu tư sẵn sàng để bán giảm mạnh từ 87.541 tỷ xuống 50.124 tỷ VND, trong đó có 720 tỷ VND nợ quá hạn và đã trích lập dự phòng. (3) Hoạt động mua nợ 6.185 tỷ VND với dự phòng 56 tỷ VND, nợ cần chú ý 444 tỷ VND. (4) Nợ khó đòi đã xử lý theo dõi ngoại bảng 60.160 tỷ VND - mức rất lớn, cho thấy rủi ro tín dụng lịch sử cao.', 5, 'VPBank là ngân hàng thương mại lớn với tổng tài sản 879.836 tỷ VND (tăng 13,4% YoY). Kết quả kinh doanh riêng năm 2024 tăng trưởng mạnh: lợi nhuận sau thuế 14.641 tỷ VND (tăng 36%), thu nhập lãi thuần 36.334 tỷ VND (tăng 37,7%). Tuy nhiên, chi phí dự phòng rủi ro tín dụng tăng 31% lên 16.420 tỷ VND phản ánh rủi ro tín dụng gia tăng. Nợ xấu nội bảng (Nhóm 3-5) chiếm 3,04% dư nợ cho vay (18.745 tỷ VND). Ngân hàng có 4 công ty con lớn với vốn điều lệ tổng cộng 27.308 tỷ VND, trong đó VPB SMBC FC (liên doanh với SMBC) có vốn 10.928 tỷ VND. SMBC với tư cách cổ đông lớn và đối tác chiến lược mang lại lợi thế về quản trị và nguồn lực tài chính nhưng cũng tạo rủi ro tập trung giao dịch. Chính sách cơ cấu nợ theo Thông tư 02/06/53 hỗ trợ khách hàng khó khăn nhưng có thể che giấu nợ xấu tiềm ẩn. Triển vọng: tăng trưởng tín dụng mạnh (24,5% YoY) vào bất động sản (27,13%) và bán lẻ nhưng cần giám sát chặt chẽ chất lượng tín dụng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VPB_2024_consolidated', 'VPB', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là với cổ đông lớn SMBC và các công ty có liên quan đến HĐQT. Các giao dịch này được thực hiện theo điều kiện thị trường và không có dấu hiệu bất thường. Tổng giá trị giao dịch với SMBC là lớn nhưng được minh bạch trong báo cáo.', 'Nợ phải trả chủ yếu từ tiền gửi khách hàng và phát hành giấy tờ có giá, với cơ cấu kỳ hạn hợp lý. Ngân hàng có tỷ lệ an toàn vốn cao và tài sản thế chấp lớn cho các khoản cho vay, giảm thiểu rủi ro nợ.', 'Ngân hàng không có hàng tồn kho truyền thống. Chỉ có khoản xây dựng cơ bản dở dang với giá trị nhỏ, không đáng kể.', 3, 'VPBank có sức khỏe tài chính tốt với lợi nhuận tăng mạnh 88,21% so với năm trước. Biên lợi nhuận cải thiện, nợ xấu được kiểm soát. Triển vọng đầu tư tích cực, nhưng cần theo dõi rủi ro từ nợ xấu và biến động thị trường.'),
('VPB_2022_consolidated', 'VPB', 2022, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là chi phí nhận tiền gửi và số dư tiền gửi của các thành viên Hội đồng Quản trị, Ban Kiểm soát và Ban Tổng Giám đốc. Giá trị không đáng kể và không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Ngân hàng có nợ phải trả lớn bao gồm vay từ Chính phủ, NHNN, các TCTC, TCTD khác và tiền gửi của khách hàng. Cơ cấu nợ đa dạng, lãi suất hợp lý, nhưng cần theo dõi áp lực thanh khoản và rủi ro lãi suất.', 'Ngân hàng không có hàng tồn kho truyền thống. Tài sản bất động sản nhận thế chấp có thể chịu rủi ro biến động giá trị, nhưng quy mô nhỏ so với tổng tài sản.', 3, 'VPBank là ngân hàng thương mại lớn tại Việt Nam với kết quả kinh doanh tăng trưởng mạnh năm 2022, lợi nhuận trước thuế tăng 47.73%. Tuy nhiên, cần lưu ý rủi ro tín dụng từ nợ xấu tăng và rủi ro thị trường từ biến động lãi suất, tỷ giá. Triển vọng đầu tư tích cực trong dài hạn nếu quản lý rủi ro hiệu quả.'),
('VPB_2022_parent', 'VPB', 2022, 'parent', 'Ngân hàng có giao dịch lớn với các công ty con (VPB SMBC FC, VPBankS, OPES, VPB AMC). Tổng nhận tiền gửi từ VPB SMBC FC là 302,580 tỷ VNĐ; gửi tiền tại VPB SMBC FC là 72,600 tỷ VNĐ. Giao dịch tăng vốn lớn vào VPBankS (15,083 tỷ) và OPES (584 tỷ). Giao dịch mua nợ từ VPB SMBC FC là 4,570 tỷ. Các giao dịch này phục vụ mục đích quản trị tập đoàn, tuy nhiên quy mô giao dịch liên quan đến VPB SMBC FC là rất lớn, cần giám sát chặt chẽ. Tổng thù lao HĐQT, Ban KS và Ban TGĐ khoảng 73.355 tỷ VNĐ/năm, ở mức hợp lý.', 'Tổng nợ phải trả đạt 492,664 tỷ VNĐ, gấp 5.16 lần vốn chủ sở hữu (95,548 tỷ). Tiền gửi khách hàng chiếm phần lớn (307,253 tỷ - 62.4%), cho thấy sự phụ thuộc lớn vào nguồn huy động. Nợ vay các TCTC/TCTD khác là 75,462 tỷ VNĐ tăng mạnh so với năm trước (59,364 tỷ). Phát hành giấy tờ có giá 36,015 tỷ. Dư nợ cho vay khách hàng tăng mạnh 29.2% (từ 279,870 tỷ lên 361,673 tỷ). Nợ xấu (nhóm 5) tăng mạnh từ 1,019 tỷ lên 4,762 tỷ (tăng 367%). Tổng tài sản thế chấp của khách hàng đạt 1,352,039 tỷ VNĐ, chủ yếu là bất động sản (571,890 tỷ) và tài sản đảm bảo khác (478,922 tỷ), cung cấp mức đệm bảo vệ tốt cho danh mục cho vay.', 'Ngân hàng không có hàng tồn kho theo nghĩa truyền thống. Dự phòng rủi ro cho vay khách hàng đạt 5,509 tỷ (gồm dự phòng chung 2,677 tỷ và dự phòng cụ thể 2,832 tỷ). Dự phòng mua nợ 41 tỷ. Dự phòng chứng khoán đầu tư 253 tỷ. Dự phòng đầu tư dài hạn 44 tỷ. Nợ khó đòi đã xử lý theo dõi ngoại bảng là 37,333 tỷ VNĐ, giảm so với năm trước (44,383 tỷ), cho thấy tiến triển tích cực trong thu hồi nợ.', 3, 'VPBank là ngân hàng lớn, có tổng tài sản 588,212 tỷ VNĐ. Năm 2022, lợi nhuận sau thuế đạt 19,209 tỷ VNĐ (giảm so với 31,088 tỷ năm 2021 do giảm thu nhập từ thoái vốn đầu tư). Thu nhập lãi thuần tăng 32.1% đạt 25,606 tỷ. Tuy nhiên, chi phí dự phòng rủi ro tín dụng tăng mạnh (8,744 tỷ vs 7,863 tỷ). Dư nợ cho vay tăng trưởng mạnh 29.2% phản ánh chiến lược mở rộng tín dụng. Tỷ lệ nợ xấu tăng (nhóm 5 tăng 367%) là điểm đáng lo ngại. Ngân hàng đã hoàn thành sáp nhập VPBankS và OPES trong năm, mở rộng đa dạng hóa dịch vụ. Vốn chủ sở hữu đạt 95,548 tỷ, tỷ lệ an toàn vốn CAR tốt. Tổng thể, VPBank có nền tảng tài chính vững mạnh với đa dạng hóa dịch vụ, nhưng cần kiểm soát tốc độ tăng trưởng tín dụng và quản lý nợ xấu hiệu quả.'),
('VPB_2021_consolidated', 'VPB', 2021, 'consolidated', 'Giao dịch với các bên liên quan (Thành viên HĐQT, BKS, Ban Tổng Giám đốc) chủ yếu bao gồm tiền gửi ngân hàng và chi phí lương/thù lao. Giá trị giao dịch so với tổng tài sản và quy mô hoạt động của ngân hàng là không đáng kể, không có dấu hiệu giao dịch bất thường, cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Ngân hàng có cấu trúc nợ đa dạng từ nhiều nguồn (NHNNVN, TCTD, khách hàng, phát hành giấy tờ có giá). Áp lực nợ vay ở mức trung bình khi tỷ lệ nợ phải trả/tổng tài sản là 84%. Tuy nhiên, ngân hàng có tài sản bảo đảm lớn (hơn 1.000 tỷ VND) và hệ số an toàn thanh khoản (LCR) được duy trì. Lãi suất nợ chủ yếu là biến động theo thị trường.', 'Hàng tồn kho và dự án xây dựng dở dang chiếm tỷ trọng rất nhỏ trong tổng tài sản. Giá trị xây dựng cơ bản dở dang chỉ có 407 triệu VND, không có dấu hiệu ứ đọng hay rủi ro đáng kể.', 3, 'Ngân hàng Thịnh Vượng (VPB) có kết quả kinh doanh tăng trưởng tốt năm 2021 (lợi nhuận trước thuế tăng 10,33%), với thu nhập lãi thuần tăng 2.003 tỷ VND. Tuy nhiên, chi phí dự phòng rủi ro tín dụng tăng mạnh (4.597 tỷ VND) cho thấy chất lượng tín dụng có dấu hiệu áp lực. Ngân hàng có cơ sở vốn vững chắc, hệ số an toàn đạt chuẩn và đa dạng hóa nguồn huy động. Triển vọng phụ thuộc vào kiểm soát chất lượng tín dụng và quản lý rủi ro thị trường trong môi trường lãi suất biến động.'),
('VPB_2021_parent', 'VPB', 2021, 'parent', 'Ngân hàng có giao dịch đáng kể với các công ty con là VPB SMBC FC (50% sở hữu) và VPB AMC (100% sở hữu). Số dư tiền gửi có kỳ hạn tại VPB SMBC FC lên tới 7,840 tỷ VNĐ, tiền gửi của VPB SMBC FC tại VPBank là 980 tỷ VNĐ và 135 tỷ VNĐ không kỳ hạn. Ngân hàng cũng nhận lợi nhuận chuyển về 3,600 tỷ từ VPB SMBC FC trong năm. Giao dịch với thành viên HĐQT, Ban Kiểm soát bao gồm tiền gửi ngân hàng 65 tỷ VNĐ. Các giao dịch này có giá trị lớn nhưng được thực hiện theo quy định nội bộ và tuân thủ pháp luật, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường.', 'Tổng nợ phải trả lên tới 408,403 tỷ VNĐ, tỷ lệ nợ/vốn chủ sở hữu là 5.37 lần. Tiền gửi khách hàng chiếm tỷ trọng lớn nhất (239,129 tỷ VNĐ), tạo áp lực duy trì thanh khoản. Nợ vay từ TCTD/TCTC là 107,000 tỷ VNĐ bao gồm vay từ IFC 254 triệu USD. Ngân hàng đã phát hành trái phiếu quốc tế 300 triệu USD với lãi suất 6.25%/năm đáo hạn tháng 7/2022. Về tài sản thế chấp, tổng giá trị tài sản đảm bảo nhận vào là 1,036,550 tỷ VNĐ, trong đó bất động sản chiếm 434,602 tỷ VNĐ, giấy tờ có giá 254,592 tỷ VNĐ. Tỷ lệ an toàn vốn và thanh khoản được duy trì theo quy định NHNN.', 'Ngân hàng không có hàng tồn kho hay dự án xây dựng dở dang theo nghĩa truyền thống. Tuy nhiên, Ngân hàng có tài sản bảo đảm nhận thay thế từ khách hàng là bất động sản trị giá 263 tỷ VNĐ (giảm từ 407 tỷ năm trước), chi phí trả trước chờ phân bổ 777 tỷ VNĐ, và xây dựng cơ bản dở dang 407 triệu VNĐ. Các tài sản này có thể chịu rủi ro thanh khoản và mất giá trị do biến động thị trường bất động sản.', 5, 'Ngân hàng TMCP Việt Nam Thịnh Vượng (VPBank) năm 2021 ghi nhận kết quả kinh doanh ấn tượng với lợi nhuận trước thuế 37,963 tỷ VNĐ, tăng 308% so với năm trước, chủ yếu nhờ thu nhập từ thoái vốn công ty con (23,948 tỷ VNĐ) và tăng thu nhập lãi thuần 4,408 tỷ VNĐ. Tổng tài sản đạt 484,442 tỷ VNĐ, tăng 34.5%. Tuy nhiên, nợ xấu cho vay khách hàng ở nhóm 3-5 là 5,630 tỷ VNĐ (chiếm 2% dư nợ cho vay). Ngân hàng có tỷ lệ đòn bẩy cao với tổng nợ phải trả gấp 5.4 lần vốn chủ sở hữu. Dòng tiền hoạt động kinh doanh thuần dương 7,594 tỷ VNĐ. Ngân hàng có nền tảng vững với mạng lưới rộng (66 chi nhánh, 168 PGD) và sự tham gia của đối tác chiến lược SMBC. Triển vọng tích cực trong trung hạn nhờ tăng trưởng tín dụng mạnh và đa dạng hóa thu nhập.'),
('VPB_2020_consolidated', 'VPB', 2020, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là tiền gửi tiết kiệm của thành viên HĐQT, BKS, Ban Tổng Giám đốc (31.851 triệu VND) và chi phí thù lao/lương (94.112 triệu VND). Đây là giao dịch bình thường của ngân hàng. VPB có hai công ty con 100%: VPB AMC (quản lý nợ) và VPB FC (công ty tài chính tiêu dùng, vốn điều lệ 7.328 tỷ VND). Chi tiết giao dịch giữa VPB và các công ty con không được thuyết minh riêng biệt trong báo cáo. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với bên liên quan.', 'Tổng nợ phải trả 366.233.025 triệu VND, tỷ lệ nợ/vốn chủ sở hữu khoảng 6,9 lần – đặc trưng cho ngân hàng thương mại. VPB huy động vốn chủ yếu từ tiền gửi khách hàng (233.428 tỷ VND, chiếm 63,7% tổng nợ) và phát hành giấy tờ có giá (62.845 tỷ VND). Ngân hàng có trái phiếu quốc tế 300 triệu USD lãi suất 6,25% đáo hạn trong 36 tháng và vay IFC 318 triệu USD. Rủi ro tỷ giá ngoại tệ đáng kể do vay ngoại tệ lớn. Lãi suất vay TCTD dao động rộng (0,75%-8,20%/năm) phản ánh đa dạng nguồn vốn.', 'VPB là ngân hàng thương mại, không có hàng tồn kho hay dự án xây dựng dở dang theo nghĩa truyền thống. Tài sản Có khác bao gồm chi phí trả trước chờ phân bổ (1.893.821 triệu VND) và tài sản bảo đảm nhận thay (439.839 triệu VND bất động sản). Rủi ro từ bất động sản nhận bảo đảm có thể tăng nếu thị trường bất động sản suy giảm.', 4, 'VPBank là một trong những ngân hàng tư nhân lớn nhất Việt Nam với tổng tài sản 419.027 tỷ VND. Lợi nhuận trước thuế 2020 đạt 13.019 tỷ VND, tăng 26,1% so với năm 2019. Tuy nhiên, chi phí dự phòng rủi ro tín dụng tăng mạnh lên 14.622 tỷ VND (tăng 934 tỷ), phản ánh tác động của COVID-19. Ngân hàng đã thực hiện cơ cấu nợ theo Thông tư 01 cho khách hàng bị ảnh hưởng dịch bệnh. Chất lượng tín dụng có dấu hiệu áp lực với nợ dưới tiêu chuẩn, nghi ngờ và có khả năng mất vốn chiếm khoảng 3,4% tổng dư nợ cho vay. NIM (biên lãi ròng) đạt khoảng 8,5% – cao hơn mức trung bình ngành do chiến lược tập trung vào cho vay tiêu dùng (41,46%/năm cho vay tiêu dùng VND). Vốn chủ sở hữu 52.794 tỷ VND, tỷ lệ an toàn vốn ổn định. Triển vọng phụ thuộc vào diễn biến dịch COVID-19 và chất lượng tài sản trong trung hạn.'),
('VPB_2019_consolidated', 'VPB', 2019, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là chi phí lương và tiền gửi của ban lãnh đạo, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay lớn với tổng nợ phải trả đạt 334.994 tỷ đồng, nhưng đa dạng nguồn huy động. Ngân hàng có tài sản thế chấp lớn (hơn 653.826 tỷ đồng) đảm bảo an toàn cho các khoản cho vay.', 'Ngân hàng không có hàng tồn kho vật lý. Rủi ro chủ yếu đến từ chất lượng tín dụng và đầu tư chứng khoán, đã được trích lập dự phòng đầy đủ.', 2, 'Ngân hàng có kết quả kinh doanh tăng trưởng tốt với lợi nhuận trước thuế tăng 12,24%. Tuy nhiên, nợ vay lớn đòi hỏi quản lý thanh khoản chặt chẽ. Hệ thống quản trị rủi ro được xây dựng bài bản, tuân thủ Basel II.'),
('VPB_2020_parent', 'VPB', 2020, 'parent', 'Các giao dịch với bên liên quan chủ yếu là giao dịch tài chính bình thường giữa ngân hàng và các công ty con, không có dấu hiệu bất thường hay giao dịch không công bằng. Giá trị giao dịch lớn nhưng phù hợp với quy mô hoạt động.', 'Ngân hàng có mức nợ phải trả cao, chiếm tỷ trọng lớn trong tổng tài sản. Tuy nhiên, nợ được đảm bảo bằng tài sản thế chấp phong phú (bất động sản, giấy tờ có giá). Lãi suất vay dao động trong khoảng hợp lý. Áp lực nợ vay ở mức trung bình, cần theo dõi khả năng thanh khoản.', 'Hàng tồn kho và dự án xây dựng có giá trị không đáng kể so với tổng tài sản, không có rủi ro ứ đọng hay chậm tiến độ.', 3, 'Ngân hàng Thương mại Cổ phần Việt Nam Thịnh Vượng có tình hình tài chính ổn định, lợi nhuận trước thuế tăng trưởng 7,9% so với năm trước. Các chỉ tiêu an toàn tuân thủ quy định. Tuy nhiên, cần chú ý đến rủi ro tín dụng từ hoạt động cho vay và nợ vay, đặc biệt trong bối cảnh kinh tế chịu ảnh hưởng của đại dịch Covid-19. Triển vọng đầu tư trung bình đến tích cực.'),
('VPB_2019_parent', 'VPB', 2019, 'parent', 'Giao dịch với công ty con VPB FC và VPB AMC chủ yếu là các nghiệp vụ ngân hàng thông thường (gửi tiền, vay, mua nợ, dịch vụ tư vấn, phái sinh) và được thực hiện theo giá thị trường. Không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Lợi nhuận chuyển về từ VPB FC đóng góp đáng kể vào kết quả kinh doanh của ngân hàng mẹ.', 'Nợ vay tập trung lớn vào tiền gửi của khách hàng (chiếm phần lớn tổng nợ), tạo áp lực tái đầu tư và rủi ro lãi suất. Ngân hàng duy trì tỷ lệ dự trữ bắt buộc và có tài sản thanh khoản cao (tiền mặt, tiền gửi tại NHNN, trái phiếu chính phủ) để đảm bảo khả năng thanh toán. Tuy nhiên, cấu trúc nợ ngắn hạn lớn đòi hỏi quản lý thanh khoản chặt chẽ.', 'Ngân hàng không có hàng tồn kho truyền thống. Khoản xây dựng cơ bản dở dang có giá trị nhỏ, rủi ro thấp. Tài sản thế chấp nhận về từ bên bảo đảm có thể thanh lý được nhưng cần thời gian xử lý.', 3, 'VPBank là ngân hàng thương mại cổ phần lớn, tăng trưởng lợi nhuận trước thuế 8.73% năm 2019. Nguồn thu nhập chính từ hoạt động tín dụng và dịch vụ. Ngân hàng có hệ thống quản trị rủi ro chặt chẽ, được kiểm toán bởi Ernst & Young. Rủi ro chính đến từ tập trung nợ ngắn hạn và rủi ro lãi suất. Triển vọng trung hạn ổn định do nền tảng kinh doanh vững chắc.'),
('VPB_2018_consolidated', 'VPB', 2018, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là chi phí lương, phụ cấp cho Ban lãnh đạo (82.826 triệu đồng) và tiền gửi tiết kiệm của họ tại Ngân hàng (53.314 triệu đồng). Quy mô giao dịch nhỏ so với tổng tài sản. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với các bên liên quan.', 'Tỷ lệ nợ phải trả trên vốn chủ sở hữu rất cao (8.3 lần), đặc trưng cho hoạt động ngân hàng. Tổng nợ ngắn hạn chiếm tỷ trọng lớn (tiền gửi khách hàng 170.851 tỷ đồng, phát hành giấy tờ có giá 48.658 tỷ đồng). Ngân hàng có đa dạng nguồn huy động từ khách hàng, TCTD khác, NHNN và phát hành chứng chỉ/trái phiếu. Tài sản thế chấp lớn (523.563 tỷ đồng) bao gồm bất động sản, động sản, giấy tờ có giá. Khoản vay chuyển đổi từ IFC (57 triệu USD) đáo hạn 31/05/2019 có thể gây áp lực.', 'Rủi ro tồn kho thấp do bản chất hoạt động ngân hàng. Bất động sản nhận từ xử lý nợ (700.474 triệu đồng) đã giảm mạnh so với năm trước, cho thấy tiến độ xử lý tốt. Xây dựng dở dang tăng nhẹ (40.034 triệu đồng) liên quan đến đầu tư cơ sở vật chất.', 4, 'VPBank duy trì tốc độ tăng trưởng mạnh với lợi nhuận trước thuế đạt 9.198 tỷ đồng (tăng 13.1%). Thu nhập lãi thuần tăng 19.9% nhờ mở rộng quy mô cho vay. Tuy nhiên, chi phí dự phòng rủi ro tín dụng tăng mạnh 40.6% (11.253 tỷ đồng) phản ánh nợ xấu gia tăng. Dư nợ nợ có khả năng mất vốn tăng 74% (từ 1.067 lên 1.857 tỷ đồng). Vốn điều lệ tăng mạnh từ 15.706 lên 25.300 tỷ đồng. Ngân hàng có hệ thống quản trị rủi ro tốt với Ủy ban ALCO và RCO. Triển vọng tích cực nhờ thị trường tiêu dùng và bán lẻ tăng trưởng, nhưng cần giám sát chặt chất lượng tín dụng bất động sản (chiếm 19.5% dư nợ).');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VPB_2017_consolidated', 'VPB', 2017, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là chi phí lương và phụ cấp cho ban lãnh đạo, không phát hiện giao dịch bất thường hay rủi ro đáng kể.', 'Ngân hàng có tổng nợ phải trả lớn, tập trung vào tiền gửi của khách hàng và phát hành giấy tờ có giá. Áp lực nợ vay cao nhưng được hỗ trợ bởi danh mục tài sản đa dạng. Tài sản thế chấp chính là bất động sản và giấy tờ có giá.', 'Ngân hàng không có hàng tồn kho hoặc dự án xây dựng dở dang, nên rủi ro tồn kho thấp.', 6, 'Ngân hàng có tình hình tài chính mạnh, với lợi nhuận tăng trưởng và quy mô tài sản mở rộng. Tuy nhiên, nợ vay cao và chi phí dự phòng rủi ro tín dụng tăng, cần theo dõi áp lực thanh khoản và chất lượng tín dụng. Triển vọng đầu tư tích cực nhờ vào mạng lưới rộng và hoạt động kinh doanh đa dạng.'),
('VPB_2018_parent', 'VPB', 2018, 'parent', 'Ngân hàng có giao dịch lớn với hai công ty con sở hữu 100% (VPB FC và VPB AMC), bao gồm: tiền gửi qua lại lên đến hàng chục nghìn tỷ đồng, bán nợ từ VPB FC cho VPBank trị giá 501.972 triệu đồng, doanh thu từ dịch vụ tư vấn và hợp đồng phái sinh. Đặc biệt, VPBank mua lại toàn bộ cổ phiếu ưu đãi (73.219.600 cổ phiếu) trị giá 2.489.232 triệu đồng làm cổ phiếu quỹ trong năm 2018. Giao dịch với công ty con là hợp lý do sở hữu 100% nhưng cần theo dõi sát sao tính công bằng của giá chuyển nhượng nợ và phí dịch vụ nội bộ. Không phát hiện giao dịch bất thường rõ ràng với bên liên quan không phải công ty con.', 'Ngân hàng có tỷ lệ nợ/vốn chủ sở hữu rất cao (~7.98 lần), đặc biệt nợ ngắn hạn chiếm 76% tổng nợ phải trả. Tiền gửi khách hàng là nguồn vốn chủ lực (167.561.668 triệu đồng, chiếm 68.8% tổng nợ). Ngân hàng có các khoản vay từ IFC với quyền chuyển đổi thành cổ phiếu (57.000.000 USD), phát hành giấy tờ có giá 24.839.922 triệu đồng với lãi suất 5,30%-10,49%/năm. Áp lực thanh toán nợ ngắn hạn rất lớn với 185.126.289 triệu đồng đến hạn trong vòng 12 tháng. Nợ xấu (nhóm 3-5) chiếm 2.72% dư nợ cho vay, nợ cần chú ý (nhóm 2) chiếm 3.73%. Tổng tài sản thế chấp đạt 517.412.309 triệu đồng, bao gồm bất động sản (223.266.429 triệu đồng) và giấy tờ có giá (120.682.627 triệu đồng).', 'Ngân hàng không có hàng tồn kho truyền thống. Bất động sản nhận từ xử lý nợ vay trị giá 662.011 triệu đồng giảm mạnh 64.5% so với năm trước, cho thấy ngân hàng đã tích cực xử lý tài sản đảm bảo. Xây dựng cơ bản dở dang tăng lên 40.034 triệu đồng. Rủi ro tồn kho không đáng kể đối với hoạt động ngân hàng.', 6, 'VPBank tăng trưởng mạnh trong năm 2018 với lợi nhuận trước thuế đạt 7.933.869 triệu đồng (tăng 41% so với năm 2017), vốn điều lệ tăng 61.7% lên 25.299.680 triệu đồng. Tổng tài sản đạt 274.158.200 triệu đồng. Tuy nhiên, ngân hàng đối mặt với một số rủi ro: (1) Tỷ lệ nợ/vốn chủ sở hữu cao (~7.98 lần), chủ yếu từ tiền gửi ngắn hạn; (2) Nợ xấu tăng với dư nợ nhóm 5 (có khả năng mất vốn) tăng 76.8% lên 1.852.622 triệu đồng; (3) Tập trung vào bất động sản với 23.49% dư nợ cho vay; (4) Giao dịch nội bộ lớn với công ty con VPB FC. Điểm tích cực: mạng lưới rộng (164 phòng giao dịch), thu nhập từ dịch vụ tăng 66.9%, và có khoản vay chuyển đổi từ IFC 57 triệu USD thể hiện niềm tin từ nhà đầu tư quốc tế. Ngân hàng đã mua lại toàn bộ cổ phiếu ưu đãi làm cổ phiếu quỹ trong năm, cho thấy chiến lược đơn giản hóa cấu trúc vốn.'),
('VPB_2017_parent', 'VPB', 2017, 'parent', 'Giao dịch với công ty con VPB FC khá đa dạng bao gồm mua bán nợ, dịch vụ tư vấn, hợp đồng phái sinh và tiền gửi với tổng giá trị giao dịch phát sinh trong năm đáng kể. Ngân hàng tăng vốn đầu tư vào VPB FC thêm 1.684 tỷ VNĐ trong năm 2017. Giao dịch bán nợ giữa ngân hàng mẹ và công ty con cần được giám sát chặt chẽ để tránh xung đột lợi ích. VPB AMC nhận ủy thác quản lý nợ với chi phí hợp đồng 130 tỷ VNĐ. Các giao dịch với thành viên HĐQT/BKS/BTGD chủ yếu là lương và tiền gửi cá nhân, không có dấu hiệu bất thường lớn. Báo cáo có trình bày đầy đủ thông tin về các bên liên quan theo quy định.', 'Tổng nợ phải trả đạt 208.154 tỷ VNĐ, gấp khoảng 8 lần vốn chủ sở hữu (25.912 tỷ VNĐ), phản ánh đặc thù hoạt động ngân hàng thương mại. Tiền gửi khách hàng chiếm tỷ trọng lớn nhất (129.057 tỷ VNĐ), trong đó tiền gửi có kỳ hạn chiếm đa số. Phát hành giấy tờ có giá tăng mạnh từ 28.845 tỷ lên 41.261 tỷ VNĐ (tăng 43%). Nợ vay TCTD khác ở mức 18.239 tỷ VNĐ với phần lớn đáo hạn trong vòng 6 tháng. Tài sản thế chấp đảm bảo cho hoạt động cho vay đạt 399.434 tỷ VNĐ (bất động sản 173.450 tỷ, động sản 39.906 tỷ, giấy tờ có giá 79.901 tỷ). Ngân hàng có tỷ lệ dự trữ bắt buộc tuân thủ quy định NHNN.', 'Ngân hàng có tài sản nhận gán nợ bất động sản trị giá 1.865 tỷ VNĐ từ khách hàng vay quá hạn, đang trong quá trình xử lý thu hồi nợ. Xây dựng cơ bản dở dang chỉ 10 tỷ VNĐ, không đáng kể. Dự phòng rủi ro cho vay khách hàng đạt 2.084 tỷ VNĐ (tỷ lệ 1.5% trên dư nợ cho vay). Nợ xấu (nhóm 3-5) chiếm 2.87% tổng dư nợ cho vay. Tổng nợ có khả năng mất vốn (nhóm 5) là 1.048 tỷ VNĐ. Ngân hàng đã bán nợ xấu cho VAMC với trái phiếu đặc biệt mệnh giá 4.048 tỷ VNĐ, đã trích lập dự phòng 817 tỷ VNĐ.', 5, 'VPBank năm 2017 tăng trưởng mạnh mẽ với tổng tài sản đạt 234.066 tỷ VNĐ (tăng 17%), lợi nhuận sau thuế 4.780 tỷ VNĐ (tăng 65%). Vốn điều lệ tăng từ 9.181 tỷ lên 15.706 tỷ VNĐ thông qua phát hành cổ phiếu. Ngân hàng có hệ thống quản trị rủi ro theo chuẩn Basel II với mô hình 3 lớp phòng vệ. Tuy nhiên, nợ xấu nhóm 3-5 có xu hướng tăng, tỷ lệ nợ có khả năng mất vốn tăng. Chi phí dự phòng rủi ro tín dụng tăng 28% lên 2.780 tỷ VNĐ. Đòn bẩy tài chính cao là đặc thù của ngành ngân hàng nhưng cần theo dõi. Mạng lưới rộng với 53 chi nhánh, 163 phòng giao dịch và 2 công ty con. Triển vọng phát triển tích cực trong trung hạn nhờ quy mô lớn và đa dạng hóa sản phẩm, nhưng rủi ro tín dụng và quản trị bên liên quan cần được kiểm soát chặt chẽ.'),
('VPA_2025_consolidated', 'VPA', 2025, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan là cổ đông lớn và công ty cùng chủ sở hữu, chủ yếu là mua hàng và thanh toán tiền. Giá trị giao dịch lớn, đặc biệt với Công ty TNHH Thuyền viên Vipco và Công ty TNHH Nhựa đường Petrolimex. Tuy nhiên, không có thông tin về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay lớn, chủ yếu là nợ dài hạn với tài sản thế chấp là tàu. Áp lực nợ vay cao do lãi vay phải trả hàng năm lớn. Công ty đã được ngân hàng giãn nợ gốc và lãi vay trong ngắn hạn, nhưng vẫn gặp khó khăn về tài chính và có nguy cơ không hoạt động liên tục.', 'Hàng tồn kho bao gồm nguyên vật liệu và chi phí sản xuất kinh doanh dở dang. Không có dự phòng giảm giá, nhưng giá trị tồn kho giảm so với đầu năm. Rủi ro tồn kho thấp do không có dấu hiệu ứ đọng.', 7, 'Công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế vượt quá vốn chủ sở hữu và nợ ngắn hạn lớn hơn tài sản ngắn hạn. Khả năng hoạt động liên tục phụ thuộc vào hỗ trợ từ cổ đông lớn và thỏa thuận với ngân hàng. Triển vọng đầu tư tiêu cực do rủi ro cao.'),
('VPA_2024_consolidated', 'VPA', 2024, 'consolidated', 'Công ty có nhiều giao dịch mua bán hàng hóa, cung cấp dịch vụ với các bên liên quan là chủ sở hữu và công ty cùng chủ sở hữu. Giá trị giao dịch lớn, đặc biệt với Công ty TNHH Thuyền viên Vipco (hơn 13 tỷ VND mua hàng) và Công ty TNHH Nhựa đường Petrolimex (hơn 52 tỷ VND doanh thu dịch vụ). Cần xem xét tính thị trường của các giao dịch này.', 'Nợ vay và nợ thuê tài chính rất lớn, tổng cộng hơn 286 tỷ VND, trong đó nợ ngắn hạn đến hạn trả trong năm 2025 là 25,5 tỷ VND. Tài sản thế chấp chính là hai tàu VP ASPHALT 1 và 2. Công ty đang lỗ lũy kế, khả năng trả nợ phụ thuộc vào việc đàm phán ngân hàng và hỗ trợ từ chủ sở hữu.', 'Hàng tồn kho hơn 10,6 tỷ VND, bao gồm chi phí sản xuất kinh doanh dở dang (nhiên liệu cho các chuyến tàu) hơn 2 tỷ VND. Rủi ro ứ đọng tồn kho có thể tăng nếu hoạt động vận tải biển không thuận lợi.', 8, 'Công ty vận tải biển đang trong tình trạng tài chính rất khó khăn: lỗ sau thuế năm 2024 hơn 50 tỷ VND, lỗ lũy kế hơn 212 tỷ VND vượt vốn chủ sở hữu. Nợ vay lớn, dòng tiền hoạt động kinh doanh âm. Khả năng hoạt động liên tục bị nghi ngờ, phụ thuộc vào sự hỗ trợ từ ngân hàng và chủ sở hữu. Triển vọng đầu tư tiêu cực, rủi ro cao.'),
('VPA_2020_consolidated', 'VPA', 2020, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm mua bán hàng hóa và thanh toán thù lao cho ban lãnh đạo. Các giao dịch mua bán với các công ty con và công ty liên kết có thể tạo ra rủi ro về giá cả và điều kiện thanh toán, nhưng không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay dài hạn khá lớn với lãi suất thả nổi và tài sản thế chấp là tàu biển. Áp lực nợ vay giảm so với kỳ trước, nhưng vẫn cần theo dõi khả năng thanh toán và biến động lãi suất.', 'Tồn kho giảm so với đầu kỳ, không có dự phòng giảm giá. Rủi ro tồn kho thấp, nhưng cần đánh giá tính thanh khoản của nguyên vật liệu và công cụ dụng cụ.', 5, 'Công ty đã chuyển lỗ thành lãi trong năm 2020, doanh thu tăng mạnh. Nợ vay giảm nhưng vẫn ở mức cao. Công ty phụ thuộc vào các giao dịch với các bên liên quan trong cùng hệ thống. Triển vọng đầu tư trung bình, cần cải thiện quản trị và đa dạng hóa khách hàng.'),
('VPA_2022_consolidated', 'VPA', 2022, 'consolidated', 'Công ty có nhiều giao dịch mua bán và thanh toán với các bên liên quan là chủ sở hữu và công ty cùng chủ sở hữu. Giá trị giao dịch lớn, đặc biệt với Công ty TNHH Vipco Hạ Long và Công ty TNHH Nhựa đường Petrolimex. Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn, nhưng cần theo dõi do mối quan hệ sở hữu chồng chéo.', 'Công ty có gánh nặng nợ vay rất lớn, với nợ vay dài hạn lên đến 270,6 tỷ VNĐ, chủ yếu từ khoản vay đồng tài trợ để đóng tàu. Chi phí lãi vay cao (9,97 tỷ VNĐ năm 2022) và lỗ chênh lệch tỷ giá lớn. Khả năng thanh toán phụ thuộc vào gia hạn nợ và hỗ trợ từ chủ sở hữu. Tài sản thế chấp là các tàu chở dầu, giá trị còn lại 309 tỷ VNĐ.', 'Hàng tồn kho giảm từ 9,83 tỷ VNĐ xuống 8,73 tỷ VNĐ, không có dự phòng giảm giá. Thành phần chủ yếu là nguyên liệu, vật liệu. Rủi ro tồn kho thấp, nhưng cần lưu ý chi phí sản xuất kinh doanh dở dang.', 6, 'Công ty gặp khó khăn tài chính nghiêm trọng với lỗ lũy kế 147,8 tỷ VNĐ, nợ ngắn hạn vượt tài sản ngắn hạn. Khả năng hoạt động liên tục phụ thuộc vào đàm phán gia hạn nợ và hỗ trợ tài chính từ chủ sở hữu. Lĩnh vực kinh doanh vận tải biển chịu biến động tỷ giá và lãi suất. Triển vọng đầu tư rủi ro cao, cần cải thiện hiệu quả hoạt động và quản lý nợ.'),
('VPA_2023_consolidated', 'VPA', 2023, 'consolidated', 'Công ty có giao dịch mua hàng và cung cấp dịch vụ lớn với các bên liên quan thuộc hệ sinh thái Petrolimex (Công ty CP Vận tải Xăng dầu Vipco - chủ sở hữu; Tổng công ty Hóa dầu Petrolimex - chủ sở hữu; Công ty TNHH Vipco Hạ Long, Công ty TNHH Thuyền viên Vipco, Công ty TNHH Nhựa đường Petrolimex - cùng chủ sở hữu). Tổng giá trị giao dịch mua hàng với bên liên quan năm 2023 đạt gần 8,4 tỷ VNĐ; cung cấp dịch vụ vận tải cho Công ty TNHH Nhựa đường Petrolimex đạt hơn 48,2 tỷ VNĐ (chiếm tỷ trọng lớn trong doanh thu). Các khoản trả tiền cho bên liên quan lớn hơn giá trị mua hàng cho thấy công ty đang thanh toán nợ tồn đọng từ trước. Cần lưu ý rủi ro về giá chuyển nhượng không theo giá thị trường.', 'Tổng nợ vay và nợ thuê tài chính là 275,3 tỷ VNĐ, chủ yếu là nợ dài hạn từ đồng tài trợ của PG Bank và Indovina Bank để đóng tàu VP ASPHALT 1 và VP ASPHALT 2. Lãi suất theo thỏa thuận, nợ đáo hạn cuối quý 3/2032. Chi phí lãi vay năm 2023 là 9,37 tỷ VNĐ. Lỗ chênh lệch tỷ giá do đánh giá lại khoản vay USD lên đến 10,57 tỷ VNĐ. Nợ phải trả người bán giảm mạnh từ 26,3 tỷ xuống 9,7 tỷ VNĐ. Áp lực nợ vay rất lớn, đặc biệt rủi ro tỷ giá USD/VND.', 'Hàng tồn kho tăng 20% từ 8,7 tỷ lên 10,5 tỷ VNĐ, chủ yếu là nhiên liệu cho tàu vận tải. Chi phí sản xuất kinh doanh dở dang tăng mạnh từ 87 triệu lên 866 triệu VNĐ (các chuyến vận tải chưa hoàn thành). Hàng tồn kho không trích lập dự phòng giảm giá. Rủi ro tồn kho ở mức trung bình do đặc thù ngành vận tải biển, nhiên liệu là tài sản lưu động nhanh.', 6, 'Công ty Cổ phần Vận tải Hóa dầu VP hoạt động trong lĩnh vực dịch vụ vận tải biển, thuộc hệ sinh thái Petrolimex. Năm 2023, doanh thu tăng trưởng mạnh 66% (từ 90,4 tỷ lên 149,9 tỷ VNĐ), biên lợi nhuận gộp cải thiện lên 4,75% (năm trước lỗ gộp 25,2 tỷ VNĐ). Tuy nhiên, công ty vẫn lỗ sau thuế 13,2 tỷ VNĐ (giảm 72,7% so với mức lỗ 48,5 tỷ VNĐ năm 2022). Lỗ lũy kế 161,6 tỷ VNĐ vượt quá vốn chủ sở hữu 150,8 tỷ VNĐ, vốn chủ sở hữu âm 9,9 tỷ VNĐ. Công ty có nợ vay dài hạn lớn 275,3 tỷ VNĐ từ PG Bank và Indovina Bank. Giao dịch với các bên liên quan trong hệ sinh thái Petrolimex chiếm tỷ trọng đáng kể. Công ty đang trên đà cải thiện hoạt động kinh doanh nhưng vẫn đối mặt với thách thức lớn về cơ cấu vốn và lợi nhuận. Triển vọng phụ thuộc vào khả năng cải thiện biên lợi nhuận, quản lý rủi ro tỷ giá và sự hỗ trợ từ tập đoàn mẹ.'),
('VPA_2019_consolidated', 'VPA', 2019, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm công ty mẹ, công ty con và người quản lý, nhưng không phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có khoản vay dài hạn lớn 304,598,699,618 VND, chi phí lãi vay cao (14,533,633,161 VND trong năm 2019), tạo áp lực trả nợ đáng kể. Tài sản cố định được dùng làm tài sản thế chấp.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và chi phí sản xuất dở dang, không có dự phòng giảm giá, cho thấy rủi ro tồn kho thấp nhưng cần theo dõi do công ty hoạt động trong lĩnh vực vận tải biển.', 6, 'Công ty lỗ liên tục hai năm (2018 và 2019), biên lợi nhuận gộp âm, nợ vay lớn dẫn đến chi phí tài chính cao. Tuy nhiên, dòng tiền từ hoạt động kinh doanh dương trong năm 2019, cải thiện so với năm trước. Triển vọng đầu tư thấp do gánh nặng nợ và lợi nhuận âm.'),
('VPA_2021_consolidated', 'VPA', 2021, 'consolidated', 'Doanh nghiệp có giao dịch mua bán lớn với các bên liên quan thuộc nhóm VIPCO và Petrolimex, đặc biệt doanh thu bán hàng chủ yếu từ Công ty TNHH Nhựa đường Petrolimex, cho thấy sự phụ thuộc vào tập đoàn mẹ, có thể tiềm ẩn rủi ro về giá chuyển nhượng và ưu đãi không minh bạch.', 'Doanh nghiệp có nợ vay lớn với lãi suất biến động, chi phí lãi vay cao chiếm tỷ trọng đáng kể trong chi phí tài chính. Tài sản đảm bảo là tàu VP1 và VP2, nếu hoạt động kinh doanh không hiệu quả, có nguy cơ mất tài sản thế chấp. Áp lực trả nợ ngắn hạn và dài hạn đều cao.', 'Hàng tồn kho chủ yếu là nguyên vật liệu (chiếm phần lớn giá trị), không có dự phòng giảm giá. Hàng tồn kho dở dang thấp, rủi ro ứ đọng không cao nhưng cần theo dõi biến động giá nguyên vật liệu.', 6, 'Doanh nghiệp hoạt động trong ngành vận tải biển, năm 2021 ghi nhận lỗ ròng 18,9 tỷ VNĐ do giá vốn vượt doanh thu và chi phí lãi vay cao. Vốn chủ sở hữu bị âm lợi nhuận tích lũy, tuy nhiên, ý kiến kiểm toán là chấp nhận toàn phần và không có nghi ngờ về hoạt động liên tục. Triển vọng phụ thuộc vào khả năng kiểm soát chi phí, đàm phán lại lãi suất và tăng doanh thu từ dịch vụ vận tải.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VPA_2018_consolidated', 'VPA', 2018, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm mua bán hàng hóa và dịch vụ với các công ty cùng chủ sở hữu. Giá trị giao dịch lớn, nhưng không có dấu hiệu bất thường rõ ràng trong báo cáo.', 'Nợ vay chiếm tỷ trọng cao trong tổng nguồn vốn, với nợ dài hạn là chủ yếu (307.689.237.990 VNĐ). Chi phí lãi vay lớn (14.212.055.249 VNĐ), áp lực trả nợ cao. Tài sản cố định (giá trị còn lại 412.936.912.465 VNĐ) được thế chấp cho các khoản vay ngân hàng.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và chi phí sản xuất dở dang, không có thông tin về dự phòng giảm giá hoặc tồn kho chậm luân chuyển.', 6, 'Công ty hoạt động trong lĩnh vực vận tải biển, kết quả kinh doanh thua lỗ nặng trong năm 2018 (lỗ sau thuế 44.216.090.144 VNĐ). Nợ vay cao, tài sản thế chấp đáng kể. Tuy nhiên, không có vấn đề về hoạt động liên tục. Triển vọng đầu tư cần thận trọng do áp lực tài chính và ngành vận tải biến động.'),
('VPA_2016_consolidated', 'VPA', 2016, 'consolidated', 'Công ty có nhiều giao dịch mua bán hàng hóa và dịch vụ với các bên liên quan, bao gồm công ty mẹ, công ty con và công ty liên quan. Tổng giá trị mua hàng từ các bên liên quan trong năm 2016 lên tới khoảng 18 tỷ VND, chiếm tỷ trọng đáng kể. Tuy nhiên, không có bằng chứng cụ thể về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có khoản nợ vay dài hạn lớn (315 tỷ VND), chiếm tỷ trọng cao trong tổng tài sản. Khoản vay được đảm bảo bằng tàu vận tải và vốn tự có. Công ty phải chịu rủi ro tỷ giá do vay bằng USD và rủi ro lãi suất thả nổi. Áp lực trả nợ gốc và lãi là đáng kể.', 'Hàng tồn kho giảm so với đầu kỳ, chủ yếu là nguyên liệu, vật liệu. Chi phí sản xuất kinh doanh dở dang ở mức thấp. Không có dự án xây dựng dở dang lớn hay bất động sản tồn kho, rủi ro tồn kho không cao.', 5, 'Công ty hoạt động trong lĩnh vực vận tải hóa dầu, có kết quả kinh doanh tích cực năm 2016 với lợi nhuận sau thuế tăng mạnh. Tuy nhiên, cơ cấu vốn phụ thuộc nhiều vào nợ vay dài hạn, đặc biệt là vay bằng USD, tạo rủi ro tỷ giá và lãi suất. Hàng tồn kho được quản lý hiệu quả. Các giao dịch với bên liên quan cần được giám sát chặt chẽ để đảm bảo tính công bằng.'),
('VPA_2017_consolidated', 'VPA', 2017, 'consolidated', 'Công ty có giao dịch đáng kể với nhiều bên liên quan, bao gồm bán hàng cho Công ty TNHH Nhựa đường Petrolimex và mua hàng từ các công ty con, công ty liên quan. Mặc dù không có bằng chứng về giao dịch bất thường, nhưng cần giám sát để đảm bảo tính công bằng.', 'Công ty có nợ vay lớn chủ yếu từ ngân hàng để tài trợ đóng tàu, với tài sản đảm bảo là tàu. Áp lực trả nợ và lãi vay cao, nhưng công ty có dòng tiền từ hoạt động kinh doanh.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu và chi phí sản xuất dở dang, không có dự phòng giảm giá. Rủi ro thấp nhưng cần theo dõi tình hình thị trường.', 6, 'Công ty VP vận tải hóa dầu gặp khó khăn trong năm 2017 với lợi nhuận giảm mạnh do thị trường vận tải yếu và chi phí tăng. Tuy nhiên, công ty đã đầu tư vào tàu mới và có kế hoạch trả nợ. Triển vọng phụ thuộc vào sự phục hồi của thị trường và quản lý chi phí.'),
('VNZ_2025_consolidated', 'VNZ', 2025, 'consolidated', 'Có nhiều giao dịch với các bên liên quan, đặc biệt là các công ty liên kết và công ty có ảnh hưởng đáng kể (như Tencent, Riot Games). Các giao dịch này chủ yếu là phí bản quyền phần mềm, mua bán dịch vụ và được cho là thực hiện theo giá và điều khoản thị trường thông thường. Tuy nhiên, quy mô giao dịch lớn, đặc biệt là phí bản quyền, tạo ra sự phụ thuộc đáng kể vào một số ít nhà cung cấp liên quan.', 'Áp lực nợ vay ở mức cao với tổng nợ vay và nợ thuê tài chính lên tới hơn 2.394 tỷ VND, trong đó nợ ngắn hạn chiếm phần lớn (1.295 tỷ). Các khoản vay dài hạn được đảm bảo bằng quyền sử dụng đất, tài sản gắn liền và máy móc thiết bị. Công ty cũng có các khoản nợ thuê tài chính cho dịch vụ cloud. Khả năng thanh toán phụ thuộc vào dòng tiền hoạt động kinh doanh trong tương lai.', 'Hàng tồn kho và dự án dở dang có giá trị tương đối nhỏ (khoảng 221 tỷ VND cho hàng tồn kho và 129 tỷ cho xây dựng dở dang). Rủi ro chính nằm ở các phần mềm trò chơi đang phát triển, có thể bị suy giảm giá trị nếu không hoàn thành hoặc không đạt hiệu quả kinh doanh như kỳ vọng.', 5, 'Tập đoàn VNG đang trong giai đoạn chuyển đổi khó khăn, chịu lỗ trong năm 2025 (lỗ sau thuế 263 tỷ) và nợ ngắn hạn vượt tài sản ngắn hạn. Tuy nhiên, doanh thu vẫn tăng trưởng và dòng tiền từ hoạt động kinh doanh mạnh. Rủi ro lớn nhất là tính liên tục hoạt động và áp lực nợ vay. Công ty đang tái cơ cấu đầu tư, bán bớt các khoản đầu tư không cốt lõi. Triển vọng phụ thuộc vào khả năng cải thiện lợi nhuận mảng cốt lõi (trò chơi, fintech) và quản lý hiệu quả nợ vay.'),
('VPA_2015_consolidated', 'VPA', 2015, 'consolidated', 'Công ty có hệ sinh thái giao dịch bên liên quan phức tạp với nhóm VIPCO (chủ sở hữu 43,78%) và Petrolimex (chủ sở hữu 45,10%). Tổng giao dịch mua hàng/nhận dịch vụ từ các bên liên quan năm 2015 lên tới khoảng 14,4 tỷ đồng. Phải trả ngắn hạn cho các bên liên quan là 4,06 tỷ đồng. Đặc biệt, Công ty TNHH Nhựa đường Petrolimex trả trước 13,07 tỷ đồng. Các giao dịch này nằm trong hệ sinh thái Petrolimex nên có thể mang tính chất nội bộ, tuy nhiên mức độ lớn đòi hỏi giám sát chặt chẽ về tính thị trường.', 'Áp lực nợ vay rất lớn: Tổng nợ phải trả 378,3 tỷ đồng (chiếm 74% tổng tài sản), trong đó nợ vay dài hạn 331,6 tỷ đồng. Nợ ngắn hạn (46,7 tỷ) vượt tài sản ngắn hạn (19,5 tỷ) 27,2 tỷ đồng. Chi phí lãi vay năm 2015 là 17,7 tỷ đồng, lỗ chênh lệch tỷ giá 19,8 tỷ đồng. Tài sản cố định (tàu VP1, VP2) trị giá 490,9 tỷ đồng được dùng để thế chấp toàn bộ khoản vay. Công ty phụ thuộc lớn vào nguồn vốn vay USD, chịu rủi ro tỷ giá cao.', 'Rủi ro hàng tồn kho ở mức thấp. Tổng hàng tồn kho 7,29 tỷ đồng (chủ yếu nguyên liệu, vật liệu 7,05 tỷ) không có dự phòng giảm giá. Chi phí SXKD dở dang chỉ 223 triệu đồng, không có dấu hiệu ứ đọng. Dự án đóng tàu VP1 và VP2 đã hoàn thành và đưa vào sử dụng, ghi nhận tài sản cố định, không còn rủi ro dở dang.', 7, 'Công ty vận tải hóa dầu VP mới hoàn thành giai đoạn đầu tư lớn (tàu VP1, VP2) và bắt đầu có lợi nhuận năm 2015 (8,4 tỷ đồng sau thuế) sau nhiều năm lỗ. Biên lợi nhuận gộp 33,9% khá tốt trong ngành vận tải. Tuy nhiên, rủi ro tài chính rất cao: nợ ngắn hạn vượt tài sản ngắn hạn, lỗ lũy kế 18,8 tỷ đồng, phụ thuộc lớn vào vốn vay USD với rủi ro tỷ giá. Công ty thuộc hệ sinh thái Petrolimex/VIPCO với nhiều giao dịch nội bộ. Nếu giá dầu giảm và tỷ giá ổn định, công ty có triển vọng cải thiện lợi nhuận từ hoạt động vận tải.'),
('VNZ_2025_parent', 'VNZ', 2025, 'parent', 'Công ty có giao dịch lớn với các bên liên quan, bao gồm công ty con và công ty liên kết, với doanh thu từ phân chia, phí bản quyền, và dịch vụ. Các giao dịch được thực hiện theo giá thị trường, không có lãi suất hay tài sản đảm bảo, nhưng volume cao có thể tạo rủi ro tập trung nếu các bên liên quan gặp khó khăn tài chính.', 'Nợ ngắn hạn tập trung vào một khoản vay lớn từ Ngân hàng Hàng Hải Việt Nam với tài sản đảm bảo là quyền sử dụng đất và cổ phiếu. Áp lực nợ vay cao do nợ ngắn hạn vượt tài sản ngắn hạn, nhưng công ty có kế hoạch cải thiện dòng tiền từ hoạt động kinh doanh và tài trợ bổ sung.', 'Hàng tồn kho chủ yếu là hàng khuyến mãi và công cụ dụng cụ, với dự phòng giảm giá. Dự án xây dựng dở dang là phần mềm trò chơi, có rủi ro suy giảm giá trị nếu dự án không hoàn thành hoặc không tạo ra lợi nhuận kinh tế.', 6, 'Công ty đang trong giai đoạn khó khăn với lỗ ròng năm 2025, nhưng doanh thu tăng và lỗ giảm so với năm trước. Khả năng hoạt động liên tục phụ thuộc vào kế hoạch kinh doanh có lợi nhuận và tài trợ bổ sung. Triển vọng phụ thuộc vào ngành trò chơi trực tuyến và dịch vụ công nghệ, với rủi ro từ giao dịch bên liên quan và áp lực nợ vay.'),
('VNZ_2023_consolidated', 'VNZ', 2023, 'consolidated', 'Tập đoàn có nhiều giao dịch với các bên liên quan, chủ yếu là phí bản quyền phần mềm và dịch vụ quảng cáo với các công ty có ảnh hưởng đáng kể (như Proxima Beta, Riot Games Services, Tencent). Các giao dịch này có vẻ phù hợp với hoạt động kinh doanh cốt lõi (trò chơi trực tuyến, quảng cáo). Tuy nhiên, sự phức tạp của mạng lưới công ty con, liên kết và các giao dịch nội bộ đặt ra yêu cầu cao về giám sát và minh bạch để tránh xung đột lợi ích.', 'Áp lực nợ vay là đáng kể với tổng nợ vay ngân hàng trên 1.483 tỷ VND, phần lớn là nợ ngắn hạn. Chi phí lãi vay tăng mạnh từ 0 lên 84 tỷ VND. Các khoản vay lớn được đảm bảo bằng tài sản cố định (đất, nhà xưởng, máy móc) và cổ phiếu của công ty con (VinaData). Rủi ro tập trung vào khả năng tái tài trợ và dòng tiền hoạt động kinh doanh hiện tại chưa đủ bù đắp lỗ lũy kế, đặt áp lực lên việc duy trì các điều khoản vay.', 'Giá trị hàng tồn kho không lớn (83 tỷ VND) và đã trích lập dự phòng giảm giá. Rủi ro chính nằm ở Chi phí xây dựng cơ bản dở dang (213 tỷ VND), chủ yếu là chi phí phát triển phần mềm và trò chơi (172 tỷ VND), phản ánh đầu tư lớn vào phát triển sản phẩm mới. Cần theo dõi tiến độ và khả năng thương mại hóa thành công của các dự án này để tránh tổn thất. Tiền thuê đất trả trước lớn (267 tỷ VND) và đã được dùng làm tài sản đảm bảo.', 6, 'Công ty VNG đang trong giai đoạn khó khăn tài chính với khoản lỗ lũy kế lớn, chủ yếu do thay đổi chính sách kế toán về ghi nhận doanh thu và chi phí đầu tư phát triển mạnh mẽ. Dù ý kiến kiểm toán là chấp nhận toàn phần, nhưng nghi ngờ về hoạt động liên tục vẫn tồn tại. Điểm sáng là dòng tiền từ hoạt động kinh doanh vẫn dương và công ty có lượng tiền mặt lớn. Rủi ro chính đến từ áp lực nợ vay, hiệu quả đầu tư vào công ty liên kết chưa tốt (lỗ lũy kế lớn), và thách thức trong việc đưa các dự án phần mềm/dữ liệu vào khai thác thương mại. Triển vọng phụ thuộc vào khả năng kiểm soát chi phí, tối ưu hóa hoạt động và thành công của các sản phẩm/game mới.'),
('VNZ_2024_consolidated', 'VNZ', 2024, 'consolidated', 'VNG có mạng lưới giao dịch bên liên quan rất phức tạp với hàng chục công ty con và công ty liên kết. Các giao dịch trọng yếu bao gồm phí bản quyền phần mềm lớn với các đối tác như Proxima (539,6 tỷ VND), Riot Games (655,7 tỷ VND doanh thu phân chia), Tencent Shenzhen (52,5 tỷ VND phí bản quyền). Công ty có khoản phải thu bên liên quan 315,8 tỷ VND và phải trả bên liên quan 756,1 tỷ VND. Một phần tiền gửi ngân hàng 339 tỷ VND đang bị giới hạn giao dịch do rà soát pháp lý của cơ quan chức năng. Dự phòng đầu tư tài chính dài hạn lên đến 5.807 tỷ VND cho thấy giá trị đầu tư vào các công ty con/liên kết bị suy giảm mạnh, đặc biệt là khoản đầu tư Zion (dự phòng 4.991 tỷ VND) và các công ty liên kết (dự phòng 815 tỷ VND).', 'VND có nợ vay ngắn hạn 558 tỷ VND, trong đó vay từ Vietcombank 337,7 tỷ VND (đáo hạn 3-31/1/2025) và Maritime Bank 220,4 tỷ VND (đáo hạn 28/2-30/6/2025), lãi suất 5.5%/năm. Tài sản thế chấp bao gồm quyền sử dụng đất tại Khu Chế xuất Tân Thuận và 40 triệu cổ phần VinaData. Tổng nợ ngắn hạn (3.689 tỷ VND) vượt xa tổng tài sản ngắn hạn (1.269 tỷ VND) với mức chênh 2.420 tỷ VND, gây áp lực thanh khoản nghiêm trọng. Chi phí lãi vay năm 2024 là 49 tỷ VND. Tuy nhiên, công ty không có nợ dài hạn vay ngân hàng.', 'Hàng tồn kho của VND tương đối nhỏ (8 tỷ VND giá trị thuần), chủ yếu gồm công cụ dụng cụ và hàng khuyến mãi. Dự phòng giảm giá hàng tồn kho tăng từ 825 triệu VND lên 933 triệu VND. Chi phí xây dựng cơ bản dở dang 46 tỷ VND liên quan đến phần mềm trò chơi đang hoàn thiện, tăng mạnh từ 17,6 tỷ VND đầu năm. Rủi ro tồn kho ở mức thấp do quy mô nhỏ so với tổng tài sản, nhưng dự án phần mềm dở dang cần được theo dõi tiến độ hoàn thành.', 8, 'VND đang trong tình trạng tài chính đáng lo ngại với lỗ sau thuế 1.808 tỷ VND (tăng mạnh từ 341 tỷ VND năm trước), chủ yếu do trích lập dự phòng đầu tư tài chính dài hạn 2.164 tỷ VND vào các công ty con và liên kết. Tổng nợ vượt tổng tài sản ngắn hạn 2.420 tỷ VND, tạo nghi ngờ lớn về khả năng hoạt động liên tục. Vốn chủ sở hữu giảm từ 2.368 tỷ xuống 560 tỷ VND, lỗ lũy kế thuế chưa phân phối còn 333 tỷ VND so với 2.141 tỷ đầu năm. Tuy nhiên, doanh thu thuần tăng 22,5% lên 5.197 tỷ VND và biên lợi nhuận gộp cải thiện từ 23,3% lên 39,9%. Công ty có kế hoạch dòng tiền 12 tháng và kỳ vọng cải thiện dòng tiền từ hoạt động kinh doanh. Lỗ thuế lũy kế 3.056 tỷ VND có thể bù trừ thu nhập tương lai trong 5 năm. Nhà đầu tư cần đánh giá kỹ rủi ro suy giảm giá trị đầu tư và khả năng phục hồi kinh doanh lõi.'),
('VNZ_2023_parent', 'VNZ', 2023, 'parent', 'VNG có mạng lưới giao dịch bên liên quan cực kỳ phức tạp với hơn 50 công ty con và liên kết. Các giao dịch trọng yếu bao gồm: doanh thu phân chia với Thanh Sơn (1.160 tỷ), Adtima (486 tỷ), MPT (218 tỷ); phí bản quyền phần mềm với Riot (390 tỷ), Proxima (366 tỷ), Tencent (60 tỷ); và lợi nhuận chia từ VNGS (714 tỷ), EPI (488 tỷ), ZPS (240 tỷ). Số dư phải trả ngắn hạn cho các bên liên quan lên đến 412 tỷ (Proxima 110 tỷ, VNGS 65 tỷ, MPT 43 tỷ). Mặc dù công ty cho biết giao dịch theo giá thị trường, quy mô giao dịch với các công ty con và công ty liên quan đến Tencent là rất lớn, đáng chú ý là khoản đầu tư vào Zion có dự phòng đầu tư lên đến 3.649 tỷ VND.', 'Nợ vay ngắn hạn của Công ty là 718.480.706.210 VND từ Ngân hàng TMCP Ngoại Thương Việt Nam, đáo hạn từ tháng 1-6/2024 với lãi suất 6.0-7.3%/năm. Tài sản thế chấp bao gồm quyền sử dụng đất tại Khu Chế xuất Tân Thuận (giá trị còn lại 524 tỷ) và 40 triệu cổ phần VinaData. Công ty phát sinh lỗ 341 tỷ trong năm 2023, dòng tiền hoạt động kinh doanh âm 134 tỷ. Tuy nhiên, Công ty có khoản tương đương tiền lớn (1.162 tỷ) và tiền gửi ngân hàng (569 tỷ), tổng tiền và tương đương tiền đạt 1.732 tỷ, đủ khả năng trả nợ. Lỗ thuế lũy kế chưa chuyển là 1.960 tỷ.', 'Hàng tồn kho cuối kỳ chỉ còn 10.6 tỷ (giá gốc 11.45 tỷ, dự phòng 824 triệu), giảm so với đầu năm 11.2 tỷ. Phần mềm trò chơi đang hoàn thiện trị giá 17.1 tỷ và Dự án Campus 478 triệu là chi phí xây dựng cơ bản dở dang, tổng cộng 17.6 tỷ (giảm từ 24.9 tỷ đầu năm). Rủi ro tồn kho thấp do quy mô nhỏ so với tổng tài sản (5.888 tỷ), tuy nhiên phần mềm trò chơi dở dang cần theo dõi tiến độ hoàn thiện.', 5, 'Công ty Cổ phần VNG đang trong giai đoạn khó khăn tài chính với lỗ sau thuế 341 tỷ VND năm 2023 (tăng mạnh so với lỗ 145 tỷ năm 2022), chủ yếu do thay đổi chính sách kế toán ghi nhận doanh thu trò chơi trực tuyến trên cơ sở phi hồi tố. Tuy nhiên, Công ty có tài sản tài chính dài hạn lớn (2.385 tỷ sau dự phòng, trong đó đầu tư vào công ty con 1.540 tỷ, công ty liên kết 843 tỷ) với dự phòng đầu tư lên đến 3.649 tỷ, cho thấy hiệu quả đầu tư kém. Điểm tích cực là Công ty có vị thế tiền mặt mạnh (1.732 tỷ), dòng tiền hoạt động đầu tư dương (207 tỷ từ thu hồi đầu tư và cổ tức), và dòng tiền tài chính dương (733 tỷ từ đi vay). Doanh thu thuần 4.243 tỷ (giảm 13% so với năm trước), biên gộp 23.3%. Rủi ro chính bao gồm: (1) khả năng hoạt động liên tục còn nghi ngờ, (2) dự phòng đầu tư tài chính khổng lồ, (3) giao dịch bên liên quan phức tạp, và (4) nợ ngắn hạn đáo hạn trong 6 tháng đầu 2024. Công ty có kế hoạch phát hành cổ phiếu chiến lược tại VTH và tỷ lệ sở hữu Zion đã tăng lên 73.76% đầu 2024.'),
('VNY_2025_consolidated', 'VNY', 2025, 'consolidated', 'Có giao dịch chuyển tiền 300 triệu VND cho Chủ tịch HĐQT năm 2025. Khoản vay dài hạn 11.8 tỷ VND từ cá nhân với lãi suất 0% có dấu hiệu là giao dịch bất thường với bên liên quan, tiềm ẩn rủi ro về xung đột lợi ích và quản trị.', 'Áp lực nợ vay dài hạn thấp, chỉ 11.8 tỷ VND từ cá nhân lãi suất 0%. Công ty có vị thế tiền mặt mạnh (38.3 tỷ VND) gấp nhiều lần nợ vay, khả năng thanh toán tốt. Không có tài sản thế chấp cho khoản vay.', 'Tồn kho giảm so với đầu năm, dự phòng giảm giá đã được hoàn nhập phần lớn (từ 1.89 tỷ xuống 0.15 tỷ VND), cho thấy rủi ro tồn kho suy giảm. Không có dự án xây dựng dở dang lớn.', 7, 'Doanh nghiệp hoạt động trong ngành thuốc thú y, có doanh thu và lợi nhuận tăng trưởng tốt trong năm 2025. Tuy nhiên, tồn tại rủi ro quản trị đáng chú ý do giao dịch với bên liên quan (cho vay không lãi suất). Sức khỏe tài cơ bản lành mạnh, dòng tiền kinh doanh mạnh, nợ vay thấp. Triển vọng ổn định nhưng cần theo dõi vấn đề quản trị.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNZ_2022_consolidated', 'VNZ', 2022, 'consolidated', 'Tập đoàn có mạng lưới giao dịch bên liên quan phức tạp với hàng chục công ty con, công ty liên kết và các bên có ảnh hưởng đáng kể (đặc biệt là các thực thể liên quan đến Tencent). Các giao dịch mua phí bản quyền phần mềm từ Proxima Beta (427 tỷ VND), Riot Games Services (162 tỷ VND), Tencent Shenzhen (44 tỷ VND) chiếm tỷ trọng lớn trong giá vốn. Tổng chi phí phải trả cho bên liên quan là 166,8 tỷ VND và doanh thu từ bên liên quan là 43,2 tỷ VND. Báo cáo cho biết các giao dịch được thực hiện theo mức giá và điều khoản niêm yết thông thường trên thị trường, số dư phải thu/phải trả không có lãi suất. Mức độ rủi ro trung bình do giao dịch lớn nhưng có vẻ minh bạch.', 'Tổng nợ vay ngân hàng là 444 tỷ VND (ngắn hạn 44,4 tỷ + dài hạn 399,6 tỷ), chiếm khoảng 5% tổng tài sản. Khoản vay từ Maritime Bank với lãi suất 7,4%-12,3%/năm, được đảm bảo bằng bất động sản và tài sản hình thành từ dự án VNG Data Center. Chi phí đi vay đã được vốn hóa 26,2 tỷ VND vào dự án. Áp lực nợ vay ở mức thấp do tỷ lệ đòn bẩy thấp và mục đích vay rõ ràng cho dự án đầu tư hạ tầng chiến lược.', 'Hàng tồn kho giảm từ 119,8 tỷ xuống 90,0 tỷ VND, dự phòng giảm giá giảm từ 1,66 tỷ xuống 1,11 tỷ VND, cho thấy tồn kho được quản lý tốt. Dự án VNG Data Center tăng mạnh giá trị từ 83,7 tỷ lên 991,7 tỷ VND cho thấy tiến độ triển khai nhanh. Phần mềm trò chơi dở dang giảm mạnh từ 123,6 tỷ xuống 44,6 tỷ VND. Rủi ro tồn kho ở mức thấp, chủ yếu tập trung vào tiến độ hoàn thành dự án Data Center.', 7, 'VNG ghi nhận lỗ sau thuế TNDN hợp nhất 1.534 tỷ VND trong năm 2022 (so với lỗ 71 tỷ năm trước), chủ yếu do phần lỗ từ công ty liên kết (181,2 tỷ VND, tăng mạnh từ 8 tỷ), chi phí bán hàng và quản lý tăng mạnh. Doanh thu thuần đạt 7.800 tỷ VND tăng nhẹ, biên lợi nhuận gộp đạt 44% - mức tốt. Tuy nhiên, công ty đang trong giai đoạn đầu tư mạnh với chi phí mua sắm TSCĐ 1.386 tỷ VND và đầu tư vào đơn vị khác 1.258 tỷ VND. Tiền mặt và tương đương tiền ở mức 2.629 tỷ VND. Các khoản đầu tư vào công ty liên kết như Tiki Global, Telio, Funding Asia đều ghi nhận lỗ lớn. Lỗ thuế lũy kế chuyển sang tương lai lên đến 5.702 tỷ VND, chưa ghi nhận tài sản thuế hoãn lại cho phần lỗ này. Doanh nghiệp có triển vọng dài hạn với hạ tầng Data Center đang xây dựng nhưng rủi ro ngắn hạn cao do lỗ hoạt động kinh doanh cốt lõi.'),
('VNZ_2022_parent', 'VNZ', 2022, 'parent', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, chủ yếu là công ty con và công ty liên kết, bao gồm giao dịch mua bán, dịch vụ và đầu tư. Các giao dịch này được thực hiện theo giá thị trường và không có dấu hiệu bất thường như cho vay không lãi suất hay chênh lệch lớn, nhưng tần suất và quy mô giao dịch cao cần được theo dõi.', 'Công ty có tỷ lệ nợ cao với nợ ngắn hạn chiếm phần lớn, nhưng không có thông tin chi tiết về vay ngân hàng hay lãi suất. Áp lực nợ vay tồn tại, đặc biệt là với các khoản phải trả người bán, nhưng công ty có đủ tài sản ngắn hạn để thanh toán.', 'Hàng tồn kho có giá trị nhỏ và đã trích lập dự phòng giảm giá, rủi ro thấp. Dự án xây dựng dở dang chủ yếu là phần mềm trò chơi, có thể bị ứ đọng nếu không hoàn thành đúng tiến độ.', 6, 'Công ty ghi nhận doanh thu giảm và lỗ thuần, nhưng lỗ đã giảm so với năm trước. Tuy nhiên, công ty có hệ sinh thái rộng lớn với nhiều công ty con và liên kết, dẫn đến giao dịch nội bộ phức tạp. Tình hình tài chính ổn định về mặt thanh khoản, nhưng hiệu quả hoạt động chưa cao do chi phí lớn. Triển vọng phụ thuộc vào khả năng cải thiện lợi nhuận từ hoạt động kinh doanh chính.'),
('VNY_2024_parent', 'VNY', 2024, 'parent', 'Công ty có giao dịch đáng kể với công ty con (Công ty TNHH Thuốc Thú y TW1) bao gồm chuyển lãi về và cho vay qua các khoản phải thu. Chủ tịch HĐQT cũng có khoản vay từ công ty. Các giao dịch này có thể tiềm ẩn rủi ro về xung đột lợi ích nếu không được quản lý chặt chẽ.', 'Công ty không có nợ vay ngân hàng, nợ phải trả chủ yếu là phải trả người bán và chi phí phải trả ngắn hạn, áp lực nợ thấp.', 'Hàng tồn kho có giá trị rất nhỏ (dưới 10 triệu VNĐ), không đáng kể và không có dự phòng.', 4, 'Công ty hoạt động chính trong lĩnh vực cho thuê địa điểm kinh doanh với biên lợi nhuận gộp rất cao (khoảng 95%). Tuy nhiên, doanh thu giảm mạnh so với năm trước. Dòng tiền từ hoạt động kinh doanh âm do thay đổi vốn lưu động. Công ty có khoản đầu tư lớn vào công ty con và các khoản phải thu lớn từ công ty con này. Tình hình tài chính cơ bản ổn định, không có nợ vay, nhưng phụ thuộc lớn vào hoạt động của công ty con.'),
('VNY_2025_parent', 'VNY', 2025, 'parent', 'Doanh nghiệp có giao dịch lớn với công ty con (Công ty TNHH Thuốc Thú y TW1), bao gồm khoản phải thu dài hạn và ngắn hạn lớn (tổng cộng hơn 47.982 tỷ VNĐ) mà không có lãi suất, cho thấy nguy cơ rủi ro về dòng tiền và quản trị. Các giao dịch khác với Chủ tịch HĐQT cũng đáng lưu ý.', 'Nợ vay chủ yếu là nợ phải trả người bán và các khoản ký quỹ, không có nợ vay ngân hàng tài chính lãi suất cao. Áp lực nợ ngắn hạn ở mức vừa phải (17.210 tỷ VNĐ) và được tài trợ bởi tài sản ngắn hạn (40.640 tỷ VNĐ). Không có tài sản thế chấp nổi bật.', 'Hàng tồn kho tại ngày 31/12/2025 là 0. Có chi phí xây dựng cơ bản dở dang (324 triệu VNĐ) nhưng giá trị nhỏ, rủi ro thấp.', 5, 'Doanh nghiệp hoạt động chính là cho thuê địa điểm kinh doanh, có lợi nhuận cao (lợi nhuận gộp >97%) và dòng tiền hoạt động kinh doanh dương. Tuy nhiên, công ty có khoản đầu tư lớn vào công ty con (70.000 tỷ VNĐ) và khoản phải thu nội bộ rất lớn từ công ty con, tạo ra rủi ro tập trung và thanh khoản. Cơ cấu vốn chủ sở hữu lớn, lịch sử lỗ lũy kế đã được cải thiện. Triển vọng phụ thuộc lớn vào hiệu quả hoạt động của công ty con.'),
('VNY_2024_consolidated', 'VNY', 2024, 'consolidated', 'Có giao dịch cho vay không lãi suất với Chủ tịch Hội đồng quản trị và khoản phải trả lớn, tiềm ẩn rủi ro xung đột lợi ích.', 'Nợ vay chủ yếu là dài hạn với lãi suất 0%, áp lực trả nợ thấp, tài sản thế chấp không được đề cập.', 'Hàng tồn kho có trích lập dự phòng giảm giá nhưng tỷ trọng không lớn, rủi ro tồn kho ở mức kiểm soát.', 4, 'Công ty có sức khỏe tài chính ổn định với lợi nhuận tăng trưởng, tỷ suất lợi nhuận gộp khoảng 25%, nợ vay không lãi suất, nhưng cần theo dõi giao dịch với bên liên quan.'),
('VNY_2023_consolidated', 'VNY', 2023, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan đáng lưu ý: (1) Khoản phải thu từ Công ty TNHH Thuốc Thú y TW 1 (công ty con) trị giá ~1,57 tỷ VNĐ; (2) Các khoản phải thu khó đòi từ nhiều đối tượng liên quan khác đã trích lập dự phòng toàn bộ, bao gồm Công ty Cổ phần Thuốc Thú y Trung ương I (~5,7 tỷ VNĐ), Công ty TNHH Dược thú y Nam Dương, Công ty CP Xuất nhập khẩu Biovet, Công ty CP Thú y Thủy sản Trung ương; (3) Ông Nguyễn Anh Tuân (Chủ tịch HĐQT) có khoản phải trả 400 triệu VNĐ; (4) Các cá nhân khác như ông Lê Đức Liên có khoản phải trả ~1,37 tỷ VNĐ. Nhiều khoản phải thu đã trích lập dự phòng 100% cho thấy rủi ro thu hồi cao.', 'Nợ dài hạn giảm mạnh từ 29,8 tỷ xuống 11,8 tỷ VNĐ (-60,4%), toàn bộ là vay cá nhân với lãi suất 0%, áp lực trả nợ thấp. Công ty phát hành cổ phiếu riêng lẻ tăng vốn 20 tỷ VNĐ trong năm 2023, đồng thời trả nợ vay 20 tỷ VNĐ, cho thấy cơ cấu tài chính cải thiện đáng kể. Tuy nhiên, nợ ngắn hạn vẫn ở mức ~41,5 tỷ VNĐ, chủ yếu là phải trả người bán ~25,6 tỷ VNĐ, phản ánh mức tín dụng thương mại lớn với nhà cung cấp.', 'Tổng hàng tồn kho 19,29 tỷ VNĐ (giá gốc), dự phòng giảm giá 1,84 tỷ VNĐ, tăng từ 1,45 tỷ VNĐ đầu năm. Thành phẩm có dự phòng giảm giá cao nhất (~1,27 tỷ VNĐ, tăng từ 873 triệu), cho thấy một phần thành phẩm bị suy giảm giá trị. Hàng hóa (7,67 tỷ VNĐ) và nguyên liệu (6,85 tỷ VNĐ) là hai khoản lớn nhất nhưng chưa trích lập dự phòng cho hàng hóa. Không có dự án xây dựng dở dang tại thời điểm báo cáo (chi phí XDCB dở dang = 0, giảm từ ~3,98 tỷ VNĐ đầu năm).', 6, 'Công ty Cổ phần Thuốc Thú y Trung ương I hoạt động trong lĩnh vực sản xuất kinh doanh thuốc thú y và phân phối vắc xin. Doanh thu thuần năm 2023 đạt 94,3 tỷ VNĐ, giảm 32% so với năm 2022 (138,6 tỷ). Lợi nhuận sau thuế 3,38 tỷ VNĐ, giảm 39,6%. Biên lợi nhuận gộp đạt ~24,9%, cải thiện so với năm trước. Công ty đã tăng vốn chủ sở hữu từ 142,5 tỷ lên 162,5 tỷ VNĐ qua phát hành cổ phiếu riêng lẻ, giảm mạnh nợ dài hạn từ 29,8 tỷ xuống 11,8 tỷ VNĐ. Dòng tiền hoạt động kinh doanh dương mạnh (~16,9 tỷ VNĐ). Tuy nhiên, công ty có nhiều khoản phải thu khó đòi đã trích lập dự phòng toàn bộ (~7,27 tỷ VNĐ), giao dịch với bên liên quan phức tạp, và hàng tồn kho có xu hướng tăng dự phòng. Điểm rủi ro quản trị ở mức trung bình-cao do lịch sử nhiều khoản phải thu khó đòi từ các bên liên quan và tỷ lệ dự phòng nợ phải thu lớn.'),
('VNY_2023_parent', 'VNY', 2023, 'parent', 'Công ty có giao dịch lớn với công ty con Công ty TNHH Thuốc Thú y TW1, bao gồm chuyển tiền, lãi về, và bổ sung vốn. Số dư phải thu và phải trả với bên liên quan này ở mức cao, cho thấy sự phụ thuộc và rủi ro liên quan đến giao dịch nội bộ.', 'Nợ phải trả chủ yếu là nợ thương mại ngắn hạn với các nhà cung cấp và không có nợ vay lãi suất. Áp lực nợ thấp, nhưng cần quản lý thanh khoản.', 'Hàng tồn kho giá trị nhỏ, không có dự phòng, rủi ro thấp.', 5, 'Doanh nghiệp hoạt động cho thuê, lợi nhuận giảm từ năm 2022, lợi nhuận sau thuế 2023 là 3.18 tỷ VND. Tuy nhiên, lợi nhuận lũy kế vẫn âm (-68.52 tỷ VND), cho thấy quá khứ thua lỗ. Tình hình tài chính ổn định với nợ thấp, nhưng cần cải thiện hiệu quả kinh doanh.'),
('VNY_2022_parent', 'VNY', 2022, 'parent', 'Công ty có giao dịch đáng kể với công ty con Công ty TNHH Thuốc thú y TW1, bao gồm chuyển tiền, thu hồi tiền vay, và chuyển lãi về. Các giao dịch này có thể ảnh hưởng đến tính độc lập của công ty, nhưng không có dấu hiệu bất thường rõ ràng.', 'Nợ phải trả chủ yếu là phải trả người bán và phải trả khác, không có thông tin chi tiết về lãi suất hay tài sản thế chấp. Áp lực nợ vay không rõ ràng do thiếu thông tin về nợ vay.', 'Không có thông tin về hàng tồn kho trong báo cáo, do đó rủi ro tồn kho không được đánh giá.', 5, 'Công ty có lợi nhuận sau thuế dương năm 2022, nhưng giảm so với năm 2021. Vốn chủ sở hữu dương, nhưng lỗ lũy kế lớn đã được xử lý bằng thặng dư vốn cổ phần. Tình hình tài chính cơ bản ổn định, nhưng cần theo dõi giao dịch bên liên quan và quản lý nợ.'),
('VNY_2022_consolidated', 'VNY', 2022, 'consolidated', 'Không có giao dịch phát sinh với bên liên quan trong năm 2022, nhưng vẫn có số dư nợ phải trả với Chủ tịch HĐQT. Các khoản vay cá nhân không lãi suất có thể tiềm ẩn rủi ro lợi ích.', 'Nợ vay chủ yếu là vay dài hạn từ cá nhân không lãi suất, áp lực trả nợ thấp, nhưng việc vay từ cá nhân có thể thiếu tính minh bạch và không có tài sản thế chấp.', 'Hàng tồn kho giảm so với đầu năm, dự phòng tăng nhẹ cho nguyên liệu và thành phẩm. Dự án xây dựng nhà máy Betalactam đang triển khai, chưa phát sinh rủi ro đáng kể.', 3, 'Công ty có sức khỏe tài chính ổn định với lợi nhuận dương, nợ vay thấp, nhưng doanh thu giảm so với năm trước. Triển vọng đầu tư phụ thuộc vào hiệu quả của hoạt động sản xuất kinh doanh thuốc thú y và tiến độ dự án xây dựng nhà máy mới.'),
('VNY_2021_consolidated', 'VNY', 2021, 'consolidated', 'Có giao dịch đáng chú ý với Chủ tịch HĐQT Nguyễn Anh Tuân cho Công ty mượn 700 triệu VND không thời hạn và không tính lãi. Công ty con (CTHH thuốc thú y TW 1) có số dư giao dịch lớn với công ty mẹ (phải thu 15,7 tỷ, phải trả 24,9 tỷ). Cựu Giám đốc Lê Đức Liên có khoản vay cá nhân lớn (~173,8 tỷ VND ban đầu) được hoán đổi thành cổ phần theo tỷ lệ 12,5119:1 và thanh toán tiền mặt, cho thấy cơ cấu nợ phức tạp với cổ đông nội bộ.', 'Rủi ro nợ vay ở mức cao. Lỗ lũy kế 192,4 tỷ VND vượt vốn góp 49,9 tỷ VND, nợ ngắn hạn vượt tài sản ngắn hạn 21,8 tỷ VND. Tổng nợ phải trả 85,9 tỷ VND chiếm 55% tổng tài sản. Công ty đã thực hiện hoán đổi nợ thành cổ phần và tăng vốn lên 142,5 tỷ VND (từ 82,5 tỷ) để tái cơ cấu. Vay ngắn hạn công ty con chủ yếu là vay tín chấp lãi suất 0% từ đối tác và vay ngân hàng có thế chấp tài sản. Chi phí lãi vay giảm mạnh từ 11,4 tỷ xuống 445 triệu VND nhờ giảm nợ.', 'Rủi ro tồn kho ở mức trung bình-cao. Tổng hàng tồn kho tăng gần gấp đôi từ 15,0 tỷ lên 28,8 tỷ VND, chủ yếu do hàng hóa tăng đột biến 18 lần. Dự phòng giảm giá tăng từ 576 triệu lên 1,3 tỷ VND. Dự phòng thành phẩm tăng mạnh từ 56,6 triệu lên 781,6 triệu VND cho thấy một phần sản phẩm có nguy cơ giảm giá trị. Không có dự án xây dựng dở dang.', 7, 'Công ty Thuốc thú y Trung ương I đang trong giai đoạn tái cơ cấu tài chính sau nhiều năm thua lỗ. Năm 2021 đánh dấu bước ngoặt với lợi nhuận sau thuế 8,2 tỷ VND (so với lỗ 1,0 tỷ năm 2020), doanh thu thuần tăng 19% lên 173,8 tỷ VND. Công ty đã thành công tăng vốn từ 82,5 tỷ lên 142,5 tỷ VND và hoán đổi nợ cá nhân lớn thành cổ phần, giảm đáng kể áp lực nợ vay. Tuy nhiên, lỗ lũy kế vẫn còn 192,4 tỷ VND, nợ ngắn hạn vượt tài sản ngắn hạn, và rủi ro quản trị liên quan đến giao dịch nội bộ với ban lãnh đạo. Điểm tích cực là biên lợi nhuận gộp ~20,5% ổn định và dòng tiền hoạt động kinh doanh cải thiện. Triển vọng phụ thuộc vào khả năng duy trì lợi nhuận và tiếp tục giảm lỗ lũy kế.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNY_2021_parent', 'VNY', 2021, 'parent', 'Giao dịch với bên liên quan chủ yếu là vay mượn cá nhân không lãi suất từ Chủ tịch HĐQT, rủi ro thấp.', 'Công ty không có nợ vay tài chính tại thời điểm cuối kỳ, áp lực nợ thấp.', 'Không có hàng tồn kho, rủi ro tồn kho thấp.', 7, 'Công ty đã có lợi nhuận trong năm 2021 sau nhiều năm lỗ, nhưng vẫn còn lỗ lũy kế lớn. Việc tăng vốn điều lệ đã cải thiện cơ cấu vốn, nhưng khả năng hoạt động liên tục còn nhiều bất ổn. Triển vọng đầu tư phụ thuộc vào khả năng duy trì lợi nhuận và quản lý rủi ro.'),
('VNY_2020_consolidated', 'VNY', 2020, 'consolidated', 'Có giao dịch bất thường: Ông Nguyễn Anh Tuấn (Chủ tịch HĐQT) cho Công ty mượn tiền để nộp thuế không tính lãi. Ông Lê Đức Liên (Giám đốc) cho Công ty vay số tiền lớn 13.368 tỷ VNĐ. Các giao dịch này có thể tiềm ẩn rủi ro về xung đột lợi ích và quản trị công ty.', 'Áp lực nợ vay rất cao. Nợ ngắn hạn vượt quá tài sản ngắn hạn 209 tỷ VNĐ. Lỗ lũy kế 200 tỷ VNĐ vượt vốn chủ sở hữu 114 tỷ VNĐ. Công ty có khả năng mất khả năng thanh toán. Tài sản thế chấp chủ yếu là quyền khai thác tài sản tại 88 Trường Chinh và một số xe ô tô.', 'Hàng tồn kho có dự phòng giảm giá 576 triệu VNĐ, tuy nhiên không có dự án xây dựng dở dang. Rủi ro tồn kho ở mức trung bình do dự phòng đã được trích lập.', 9, 'Tình hình tài chính của Công ty rất xấu. Doanh nghiệp lỗ lũy kế lớn, vượt vốn chủ sở hữu, nợ ngắn hạn vượt tài sản ngắn hạn, dẫn đến nghi ngờ về khả năng hoạt động liên tục. Giao dịch với các bên liên quan phức tạp, cho vay không lãi suất với Chủ tịch HĐQT và Giám đốc cho vay lớn. Kiểm toán viên đã nhấn mạnh vấn đề này. Triển vọng đầu tư rất rủi ro.'),
('VNY_2020_parent', 'VNY', 2020, 'parent', 'Công ty có giao dịch bên liên quan phức tạp đáng lo ngại. Tổng phải thu từ công ty con (Công ty TNHH Thuốc Thú y TW 1) lên tới ~39,4 tỷ VND (bằng 41% tổng tài sản), bao gồm khoản vay dài hạn 14,8 tỷ và các khoản phải thu khác 24,7 tỷ. Giám đốc Lê Đức Liên cho công ty vay 13,4 tỷ VND (lãi suất 12%/năm), đồng thời còn phát sinh khoản lãi vay thế chấp tài sản mượn cá nhân 817 triệu VND (lãi suất 3%/năm). Chủ tịch HĐQT Nguyễn Anh Tuấn cho công ty mượn 800 triệu VND không lãi suất và không có thời hạn trả. Các giao dịch này cho thấy sự lạm dụng vị trí quản lý để tài trợ cho công ty đang kiệt quệ tài chính, đồng thời tạo rủi ro xung đột lợi ích.', 'Nợ vay ngắn hạn từ cá nhân chiếm 173,8 tỷ VND với lãi suất 12%/năm, tín chấp – con số này vượt xa tổng tài sản (~96 tỷ VND). Nợ phải trả tổng cộng 213,2 tỷ VND gấp 2,2 lần tổng tài sản. Công ty đã trả nợ gốc vay 9,8 tỷ trong năm nhưng vẫn phát sinh thêm vay mới 42,7 tỷ. Áp lực trả nợ lãi vay rất lớn (~10 tỷ/năm), ăn mòn toàn bộ doanh thu. Khả năng thanh toán độc lập gần như không thể, phụ thuộc hoàn toàn vào kế hoạch tăng vốn 60 tỷ VND từ Nghị quyết ĐHCĐ.', 'Rủi ro tồn kho đã giảm đáng kể khi toàn bộ hàng hoá tồn kho 2,277 tỷ VND đầu kỳ đã được xuất bán hết trong năm 2020, không còn tồn kho cuối kỳ. Tuy nhiên, điều này cũng cho thấy công ty không còn hàng hoá dự trữ cho hoạt động kinh doanh, đặt câu hỏi về tính liên tục của hoạt động sản xuất kinh doanh.', 8, 'Công ty Cổ phần Thuốc Thú y Trung ương I đang trong tình trạng tài chính nghiêm trọng với lỗ lũy kế 200,3 tỷ VND vượt xa vốn chủ sở hữu 82,5 tỷ VND, nợ phải trả vượt tổng tài sản. Lỗ ròng năm 2020 là 1,25 tỷ (cải thiện so với lỗ 16,8 tỷ năm 2019). Doanh thu tăng mạnh 288% lên 5,5 tỷ nhờ bán hàng hoá và tăng doanh thu cho thuê kho. Tuy nhiên, chi phí lãi vay vẫn chiếm phần lớn lợi nhuận gộp. Công ty có kế hoạch tăng vốn 60 tỷ từ nhà đầu tư chiến lược và hoán đổi nợ, đây là yếu tố sống còn cho khả năng hoạt động liên tục. Các giao dịch bên liên quan phức tạp, quản trị yếu kém, và phụ thuộc vào nguồn vốn cá nhân cho thấy rủi ro rất cao cho nhà đầu tư.'),
('VNY_2019_parent', 'VNY', 2019, 'parent', 'Doanh nghiệp có các giao dịch phức tạp với công ty con Công ty TNHH Thuốc thú y TW1 bao gồm mua bán hàng hóa, cho vay và thu hồi tiền vay. Ngoài ra, Chủ tịch HĐQT Nguyễn Anh Tuấn cho công ty vay 700 triệu VNĐ không tính lãi. Các khoản phải thu từ công ty con lên đến hàng chục tỷ đồng, gây rủi ro về thanh khoản và tính minh bạch. Không có dự phòng được trích lập cho các khoản phải thu từ bên liên quan.', 'Tổng nợ vay là 143 tỷ VNĐ, trong đó 133 tỷ VNĐ là vay cá nhân không có hợp đồng và lãi suất cao (12%/năm). Áp lực trả lãi lớn (gần 21 tỷ VNĐ chi phí lãi vay năm 2019). Tài sản đảm bảo chủ yếu là quyền sử dụng đất tại trụ sở chính. Công ty đã không thanh toán được nợ gốc đúng hạn dẫn đến bị ngân hàng xiết nợ.', 'Hàng tồn kho chủ yếu là hàng hoá thành phẩm với giá trị 2,277 tỷ VNĐ, không có dự phòng giảm giá. Rủi ro tồn kho ở mức trung bình, không có dự án xây dựng dở dang.', 8, 'Tình hình tài chính của doanh nghiệp rất nghiêm trọng. Công ty hoạt động kinh doanh thua lỗ liên tục, lỗ lũy kế vượt quá vốn chủ sở hữu. Nợ phải trả ngắn hạn lớn hơn tài sản ngắn hạn, cho thấy nguy cơ mất khả năng thanh toán cao. Các giao dịch với bên liên quan, đặc biệt là khoản cho vay lớn với công ty con và Chủ tịch HĐQT, đặt ra câu hỏi về quản trị và xung đột lợi ích. Báo cáo kiểm toán đã đưa ra ý kiến ngoại trừ về các khoản vay cá nhân không có hợp đồng. Doanh nghiệp đối mặt với rủi ro hoạt động liên tục rất lớn.'),
('VNY_2018_consolidated', 'VNY', 2018, 'consolidated', 'Có giao dịch cho vay không lãi suất, không tài sản đảm bảo giữa Chủ tịch HĐQT và Công ty, cho thấy rủi ro về xung đột lợi ích và quản trị công ty.', 'Áp lực nợ vay rất lớn, nợ phải trả vượt tài sản ngắn hạn. Công ty đang trích trước chi phí lãi vay quá hạn cho khoản vay ngân hàng Agribank nhưng chưa được ngân hàng xác nhận do đang xin miễn giảm. Các khoản vay cá nhân không có tài sản đảm bảo.', 'Hàng gửi bán 75.012.817 đồng không có biên bản gửi hàng và một phần hàng hoá tồn kho (659.408.445 đồng) đã xuất bán nhưng chưa ghi nhận doanh thu, gây rủi ro về kiểm soát và doanh thu. Hàng hoá Công ty con đã hết hạn sử dụng.', 7, 'Doanh nghiệp trong tình trạng tài chính rất khó khăn với lỗ lũy kế lớn, nợ phải trả vượt tài sản ngắn hạn, và dòng tiền hoạt động kinh doanh dương nhưng không đủ bù đắp. Kiểm toán ngoại trừ do không xác nhận được một phần khoản vay cá nhân và giá trị tồn kho. Triển vọng đầu tư tiêu cực, rủi ro cao về khả năng hoạt động liên tục.'),
('VNY_2017_consolidated', 'VNY', 2017, 'consolidated', 'Báo cáo không trình bày chi tiết các giao dịch với các bên liên quan (như mua bán, cho vay) mà chỉ ghi nhận các khoản phải thu và trả trước có liên quan. Tuy nhiên, thuyết minh chỉ rõ toàn bộ chi phí bán hàng và quản lý doanh nghiệp phát sinh của Chi nhánh Đà Nẵng và HCM trong giai đoạn 17/11-31/12/2017 (tổng cộng gần 2.8 tỷ đồng) chưa có phê duyệt của Chủ tịch HĐQT và chứng từ chưa có chữ ký của Kế toán trưởng và Giám đốc chi nhánh, cho thấy lỗ hổng trong kiểm soát nội bộ và phê duyệt giao dịch.', 'Rủi ro nợ vay cực kỳ cao. Công ty lỗ lũy kế 166.273.730.338 đồng, vượt vốn chủ sở hữu. Tại thời điểm 31/12/2017, Công ty thừa nhận không có khả năng trả các khoản nợ đến hạn (cả nợ phải trả người bán và vay nợ). Nợ vay cá nhân không có tài sản đảm bảo lên đến hơn 92.6 tỷ đồng (quá hạn). Cơ cấu nợ dựa nhiều vào vay cá nhân lãi suất cao (12%/năm) và vay ngân hàng có tài sản thế chấp là bất động sản và máy móc.', 'Rủi ro tồn kho cao do hàng hóa tồn kho đã ghi nhận dự phòng giảm giá 672.120.468 đồng. Hàng gửi bán 545.702.635 đồng (do Phó GĐ chi nhánh mang đi) và một phần hàng hóa tại các chi nhánh đã hết hạn sử dụng, không có khả năng thu hồi giá trị.', 9, 'Công ty đang trong tình trạng tài chính cực kỳ khó khăn, lỗ lũy kế vượt vốn chủ sở hữu, mất khả năng thanh toán và đối mặt với nghi ngờ lớn về hoạt động liên tục. Kiểm toán đưa ra ý kiến ngoại trừ do không thu thập được xác nhận công nợ. Các rủi ro nổi bật bao gồm: cơ cấu nợ không lành mạnh với nhiều khoản vay cá nhân không đảm bảo, nợ phải trả người bán lớn quá hạn, hàng tồn kho hư hỏng, và thiếu sót nghiêm trọng trong kiểm soát nội bộ (chứng từ chi phí tại chi nhánh không có phê duyệt và chữ ký). Triển vọng đầu tư tiêu cực.'),
('VNY_2017_parent', 'VNY', 2017, 'parent', 'Doanh nghiệp có giao dịch lớn với công ty con (Công ty TNHH Thuốc thú y trung ương 1), cụ thể phải thu khách hàng gần 49 tỷ VND và phải trả người bán gần 8,8 tỷ VND. Các giao dịch này cần được đánh giá tính công bằng và minh bạch, đặc biệt khi công ty đang trong tình trạng tài chính khó khăn.', 'Công ty có nợ vay rất lớn, tổng nợ vay lên đến hơn 149 tỷ VND, trong đó nợ ngắn hạn 35,5 tỷ và nợ dài hạn 114 tỷ. Tại thời điểm 31/12/2017, Công ty đang không có khả năng trả các khoản nợ đến hạn. Khoản vay cá nhân quá hạn chưa thanh toán lên đến 92,6 tỷ VND. Áp lực nợ vay rất cao, khả năng thanh toán bị đặt dấu hỏi nghiêm trọng.', 'Hàng tồn kho giảm mạnh từ 11,2 tỷ xuống còn 3,5 tỷ VND, có trích lập dự phòng giảm giá 583 triệu VND. Hàng gửi bán có dự phòng lớn do chưa xuất hóa đơn và ghi nhận sai quy trình. Rủi ro tồn kho ở mức trung bình do số lượng đã giảm nhưng vẫn có vấn đề về quy trình kiểm soát.', 9, 'Công ty đang trong tình trạng tài chính rất yếu với khoản lỗ lũy kế lớn vượt vốn chủ sở hữu, mất khả năng thanh toán nợ ngắn hạn. Ý kiến kiểm toán ngoại trừ do không thu thập được xác nhận công nợ từ nhiều đối tác. Ban lãnh đạo có sự biến động lớn trong năm 2017, nhiều thành viên HĐQT và Ban Giám đốc bị miễn nhiệm. Hoạt động kinh doanh chính suy giảm mạnh (doanh thu giảm từ 193,8 tỷ xuống 131,7 tỷ VND), chi phí lãi vay tăng vọt. Công ty đang đối mặt với nguy cơ mất khả năng hoạt động liên tục.'),
('VNY_2019_consolidated', 'VNY', 2019, 'consolidated', 'Giao dịch bất thường: Chủ tịch HĐQT Nguyễn Anh Tuân cho Công ty mượn tiền 700 triệu VNĐ không có thời hạn, không tính lãi, không có tài sản đảm bảo. Đây là giao dịch liên quan đến người có vị trí quản lý cao nhất, tiềm ẩn rủi ro xung đột lợi ích. Các khoản phải thu/phải trả với Công ty con TNHH thuốc thú y TW1 có giá trị lớn (hàng chục tỷ VNĐ) nhưng không được thuyết minh chi tiết về điều kiện giao dịch.', 'Áp lực nợ vay cực kỳ nghiêm trọng. Tổng nợ vay 166,8 tỷ VNĐ trong đó vay cá nhân chiếm 133,4 tỷ (80%) với lãi suất 12%/năm và không có tài sản đảm bảo, không có hợp đồng vay rõ ràng (kiểm toán viên không đủ cơ sở xác định). Nợ ngắn hạn 18,25 tỷ vượt quá tiền và tương đương tiền (31,9 tỷ). Lỗ lũy kế 199 tỷ vượt vốn chủ sở hữu 112,7 tỷ. Chi phí lãi vay 21,87 tỷ chiếm 74% lợi nhuận gộp. Nợ ngắn hạn vượt tài sản ngắn hạn 69,7 tỷ cho thấy nguy cơ mất khả năng thanh toán.', 'Dự phòng giảm giá hàng tồn kho tăng mạnh từ 355 triệu lên 667 triệu VNĐ. Tại Công ty TNHH thuốc thú y TW1, 563,8 triệu VNĐ hàng hóa đã hết hạn sử dụng và 103,5 triệu VNĐ gần hết hạn. Dự phòng nguyên liệu tăng từ 210 triệu lên 520 triệu VNĐ. Hàng tồn kho trị giá 18,2 tỷ VNĐ là tài sản lưu động lớn nhất, cần theo dõi sát khả năng tiêu thụ và nguy cơ giảm giá.', 8, 'Công ty trong tình trạng tài chính rất yếu: lỗ lũy kế 199 tỷ VNĐ vượt xa vốn chủ sở hữu 82,5 tỷ (vốn chủ sở hữu âm 112,7 tỷ); nợ ngắn hạn vượt tài sản ngắn hạn 69,7 tỷ; lưu chuyển tiền từ hoạt động kinh doanh âm 9,8 tỷ. Kiểm toán viên đưa ý kiến ngoại trừ về 3 khoản vay cá nhân 20 tỷ không có hợp đồng. Nợ vay cá nhân 133,4 tỷ với lãi suất 12%/năm là gánh nặng tài chính lớn. Tuy nhiên, công ty vẫn duy trì biên lợi nhuận gộp 21,4% và doanh thu thuần 137,6 tỷ, có tài sản cố định 103,4 tỷ. Rủi ro hủy niêm yết do lỗ lũy kế vượt 3 lần vốn chủ sở hữu. Triều vọng đầu tư rất rủi ro.'),
('VNX_2021_consolidated', 'VNX', 2021, 'consolidated', 'Không phát hiện giao dịch bất thường hay rủi ro đáng kể với các bên liên quan. Các giao dịch chủ yếu bao gồm lương thưởng cho Ban Tổng Giám đốc và Ban Kiểm soát.', 'Rủi ro nợ vay thấp. Nợ vay ngắn hạn rất nhỏ (chỉ 22.640.000 VND). Áp lực thanh toán chủ yếu đến từ các khoản phải trả người mua trước và phải trả khác, tuy nhiên Công ty có tiền và tương đương tiền cùng các khoản đầu tư ngắn hạn (tiền gửi) lớn, đảm bảo khả năng thanh toán.', 'Hàng tồn kho (chi phí SXKD dở dang) có giá trị lớn, chiếm khoảng 17,7% tổng tài sản. Dù không trích lập dự phòng, nhưng doanh thu sụt giảm mạnh trong năm 2021 do ảnh hưởng của đại dịch Covid-19 đến các hoạt động hội chợ, triển lãm, cần theo dõi khả năng thu hồi giá trị của các khoản chi phí dở dang này.', 3, 'Công ty có nền tảng tài chính tương đối an toàn với tỷ lệ nợ vay thấp và thanh khoản tốt. Tuy nhiên, hoạt động kinh doanh chịu ảnh hưởng nghiêm trọng từ đại dịch Covid-19, khiến doanh thu và lợi nhuận sụt giảm so với năm trước. Điểm tích cực là Công ty vẫn duy trì được lợi nhuận và dòng tiền từ hoạt động đầu tư (lãi tiền gửi). Triển vọng phụ thuộc vào sự phục hồi của ngành tổ chức sự kiện và du lịch.'),
('VNX_2024_consolidated', 'VNX', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là thù lao, lương, thưởng cho HĐQT và Ban kiểm soát, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay rất thấp chỉ 22.640.000 VNĐ, áp lực nợ vay không đáng kể, khả năng thanh toán tốt.', 'Hàng tồn kho là chi phí SXKD dở dang (tổ chức hội chợ chưa diễn ra), không có dự phòng, nhưng doanh nghiệp hoạt động ổn định nên rủi ro thấp.', 3, 'Công ty có tình hình tài chính lành mạnh, doanh thu và lợi nhuận tăng trưởng, dòng tiền kinh doanh dương, nợ vay thấp, quản trị ổn định.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNX_2025_consolidated', 'VNX', 2025, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là thù lao, lương thưởng cho thành viên Hội đồng quản trị, Ban kiểm soát và Ban Tổng Giám đốc, phù hợp với quy định và không có dấu hiệu bất thường. Công ty đã công bố thông tin đầy đủ về các giao dịch này.', 'Nợ vay rất thấp chỉ 22,64 triệu VNĐ, chiếm tỷ trọng nhỏ trong tổng tài sản, áp lực nợ vay không đáng kể. Công ty có khả năng thanh toán tốt với dòng tiền hoạt động kinh doanh dương mạnh.', 'Hàng tồn kho chủ yếu là chi phí SXKD dở dang cho các hội chợ chưa diễn ra, giá trị tăng nhẹ so với đầu kỳ. Rủi ro tồn kho ở mức trung bình, phụ thuộc vào tiến độ tổ chức hội chợ và khả năng thu hồi chi phí.', 3, 'Công ty có tình hình tài chính lành mạnh với doanh thu và lợi nhuận tăng trưởng tốt trong năm 2025. Dòng tiền hoạt động kinh doanh dương mạnh, nợ vay thấp, khả năng thanh toán cao. Tuy nhiên, rủi ro tập trung vào tính mùa vụ của hoạt động tổ chức hội chợ và sự phụ thuộc vào các dự án dở dang. Triển vọng đầu tư tích cực trong ngắn hạn và trung hạn.'),
('VNX_2022_consolidated', 'VNX', 2022, 'consolidated', NULL, NULL, NULL, 5, 'Không có đủ thông tin từ Báo cáo tài chính để phân tích.'),
('VNX_2020_consolidated', 'VNX', 2020, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là thù lao, lương cho ban lãnh đạo và kiểm soát. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay thấp. Công ty chỉ có một khoản vay cá nhân ngắn hạn với số tiền nhỏ 22,640,000 VND, không có tài sản thế chấp. Khả năng thanh toán nợ tốt với tiền mặt và đầu tư ngắn hạn dồi dào.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang, không có dự phòng giảm giá. Rủi ro ứ đọng trung bình do ảnh hưởng của dịch COVID-19 đến hoạt động tổ chức hội chợ.', 3, 'Công ty chịu ảnh hưởng nặng nề từ đại dịch COVID-19 khiến doanh thu và lợi nhuận sụt giảm mạnh so với năm trước. Tuy nhiên, tình hình tài cơ bản vẫn lành mạnh, không có nợ vay lớn, tài sản ngắn hạn lớn hơn nợ ngắn hạn. Công ty có đủ khả năng hoạt động liên tục.'),
('VNX_2019_consolidated', 'VNX', 2019, 'consolidated', 'Các thuyết minh về phải thu và phải trả có ghi nhận mục ''các bên liên quan'' nhưng không trình bày số liệu chi tiết (ghi dấu ''-''), cho thấy giao dịch với các bên liên quan không đáng kể trong kỳ. Không có bằng chứng về giao dịch bất thường với công ty con, công ty liên kết hay cá nhân ban lãnh đạo.', 'Áp lực nợ vay rất thấp: Công ty chỉ có khoản vay cá nhân ngắn hạn 22.640.000 VND, không có nợ dài hạn. Tỷ lệ nợ/vốn chủ sở hữu chỉ ~0.05%. Công ty có tiền mặt 9,3 tỷ VND và đầu tư ngắn hạn 37,5 tỷ VND, dư khả năng thanh toán mọi nghĩa vụ nợ.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang với giá trị 8,49 tỷ VND, tăng nhẹ so với đầu năm (8,22 tỷ). Không trích lập dự phòng giảm giá. Cần theo dõi tiến độ hoàn thành và khả năng chuyển đổi thành doanh thu của các dự án dở dang này.', 2, 'Vinexad là doanh nghiệp hoạt động ổn định trong lĩnh vực tổ chức hội chợ, quảng cáo và bất động sản cho thuê. Năm 2019, doanh thu đạt 213,5 tỷ VND (tăng 30% so với năm trước), lợi nhuận sau thuế 15,96 tỷ VND (tăng 28%). Biên lợi nhuận gộp ~17,7%. Công ty có sức khỏe tài chính tốt: tiền và đầu tư ngắn hạn lên tới 46,8 tỷ VND, nợ vay gần như không có, ROE ~39%. Chi phí quản lý doanh nghiệp tăng 20% theo đà tăng trưởng. Công ty chia cổ tức 6,1 tỷ VND và trích quỹ đầu tư phát triển, quỹ phúc lợi. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần, không có vấn đề hoạt động liên tục. Đánh giá tổng thể: triển vọng tích cực, rủi ro thấp.'),
('VNX_2018_consolidated', 'VNX', 2018, 'consolidated', 'Không phát hiện giao dịch bất thường với các bên liên quan.', 'Nợ vay rất nhỏ, không có áp lực nợ vay đáng kể.', 'Hàng tồn kho chủ yếu là chi phí sản xuất dở dang, không có dự phòng giảm giá.', 2, 'Công ty có tình hình tài chính tốt, doanh thu và lợi nhuận tăng trưởng, khả năng thanh toán mạnh.'),
('VNX_2017_consolidated', 'VNX', 2017, 'consolidated', 'Không có giao dịch đáng ngờ với các bên liên quan được công bố trong báo cáo.', 'Áp lực nợ vay rất thấp, chỉ có khoản vay cá nhân ngắn hạn 22.640.000 VNĐ, không có nợ dài hạn. Khả năng thanh toán cao nhờ dòng tiền kinh doanh mạnh.', 'Hàng tồn kho giảm nhẹ từ 7.482.588.016 VNĐ xuống 7.333.195.924 VNĐ, không trích lập dự phòng, rủi ro tồn kho thấp.', 2, 'Tổng thể tình hình tài chính lành mạnh, doanh thu và lợi nhuận tăng trưởng mạnh (LNTT tăng 46%), dòng tiền từ hoạt động kinh doanh dương lớn (12.858.183.784 VNĐ), tỷ suất lợi nhuận gộp khoảng 16,8%. Nợ vay thấp, thanh khoản tốt. Công ty có khả năng hoạt động liên tục và triển vọng tích cực.'),
('VNX_2016_consolidated', 'VNX', 2016, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là thù lao cho HĐQT, Ban Giám đốc và Ban Kiểm soát với tổng cộng 1.288.624.031 VND. Không phát hiện giao dịch mua bán, cho vay bất thường với các bên liên quan. Chủ tịch HĐQT Nguyễn Khắc Luận đồng thời là Tổng Giám đốc, cho thấy mô hình kiêm nhiệm.', 'Nợ vay rất thấp chỉ 22.640.000 VND (vay cá nhân ngắn hạn), chiếm tỷ lệ không đáng kể 0,06% trên tổng tài sản 40,97 tỷ VND. Công ty gần như không có đòn bẩy tài chính, áp lực trả nợ là không đáng kể. Khả năng thanh toán nợ tốt nhờ dòng tiền hoạt động kinh doanh dương mạnh.', 'Hàng tồn kho (chi phí SXKD dở dang) trị giá 7,48 tỷ VND, tăng 17% so với đầu năm (6,4 tỷ). Đây là chi phí triển khai triển lãm, hội chợ 2017 chưa được phân bổ. Không có dự phòng giảm giá hàng tồn kho. Rủi ro ở mức trung bình, cần theo dõi tiến độ tổ chức sự kiện để đảm bảo thu hồi chi phí.', 3, 'Công ty có sức khỏe tài chính tốt với tỷ lệ nợ vay rất thấp (0,06%), biên lợi nhuận gộp ổn định ~15%, doanh thu tăng trưởng 15,5% và lợi nhuận sau thuế tăng 63,5% so với năm trước. Dòng tiền hoạt động kinh doanh dương mạnh 6,49 tỷ VND. Tuy nhiên, công ty hoạt động trong ngành tổ chức sự kiện mang tính thời vụ, hàng tồn kho dở dang lớn cần theo dõi. Ban lãnh đạo kiêm nhiệm nhiều vị trí (Chủ tịch HĐQT kiêm Tổng Giám đốc) có thể ảnh hưởng đến tính độc lập trong quản trị. Tổng thể, doanh nghiệp có triển vọng phát triển tốt với nền tảng tài chính vững chắc.'),
('VNX_2015_consolidated', 'VNX', 2015, 'consolidated', 'Giao dịch bên liên quan chủ yếu là lương cho Hội đồng quản trị, Ban Tổng Giám đốc và Ban Kiểm soát với tổng thu nhập 1,109,576,465 VNĐ trong năm 2015, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay chủ yếu là ngắn hạn với số tiền nhỏ 22,640,000 VNĐ (vay cá nhân), áp lực nợ thấp, công ty có khả năng thanh toán từ dòng tiền hoạt động kinh doanh và các tài sản tài chính đáo hạn, tài sản thế chấp không được đề cập.', 'Hàng tồn kho là chi phí sản xuất kinh doanh dở dang 6,406,465,083 VNĐ và dự án triển lâm hội chợ 2017 dài hạn 1,103,520,000 VNĐ, không có dự phòng giảm giá, rủi ro ứ đọng thấp nhưng cần theo dõi tiến độ dự án.', 3, 'Công ty có kết quả kinh doanh ổn định với doanh thu thuần 108,032,729,833 VNĐ và lợi nhuận sau thuế 3,709,296,111 VNĐ, tăng trưởng so với năm trước. Cơ cấu tài sản hợp lý, nợ vay thấp, nhưng dự án dở dang dài hạn có thể ảnh hưởng đến dòng tiền tương lai. Triển vọng đầu tư trung bình đến tích cực.'),
('VNT_2024_consolidated', 'VNT', 2024, 'consolidated', 'Các giao dịch với bên liên quan (Vinafreight, Transimex, Cảng Mipec) chủ yếu là mua bán dịch vụ vận chuyển, logistics và chia cổ tức, có quy mô không quá lớn so với tổng doanh thu. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Tổng nợ ngắn hạn lớn (hơn 294 tỷ VND), tập trung vào vay ngân hàng với lãi suất từ 3.9% - 8%/năm. Các khoản vay được đảm bảo chủ yếu bằng tiền gửi có kỳ hạn và một số tài sản cố định (quyền sử dụng đất, phương tiện vận tải). Áp lực trả nợ ngắn hạn ở mức trung bình, khả năng thanh toán phụ thuộc vào dòng tiền hoạt động kinh doanh.', 'Không có thông tin chi tiết về hàng tồn kho trong báo cáo. Các dự án xây dựng dở dang (chi phí XDCB dở dang) có giá trị nhỏ (740 triệu VND) và đã giảm so với đầu năm, không có dấu hiệu ứ đọng.', 4, 'Công ty hoạt động trong lĩnh vực giao nhận vận tải, doanh thu năm 2024 tăng mạnh (63%) nhờ sự phục hồi của thương mại quốc tế. Lợi nhuận sau thuế dương nhưng rất nhỏ so với quy mô doanh thu. Cơ cấu vốn chủ yếu dựa vào nợ ngắn hạn, trong khi vốn chủ sở hữu có lợi nhuận chưa phân phối lũy kế âm. Công ty có đầu tư vào công ty liên kết (Cảng Mipec) đang ghi nhận lỗ theo phương pháp vốn chủ sở hữu. Điểm rủi ro quản trị ở mức trung bình do giao dịch với các cổ đông lớn và lợi nhuận thấp.'),
('VNT_2025_consolidated', 'VNT', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là dịch vụ vận tải và logistics, giá trị không lớn và được thực hiện theo giá thị trường, rủi ro thấp. Tuy nhiên, cần lưu ý các giao dịch với cổ đông lớn như Vinafreight và Transimex.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn với tổng số dư 268.679.394.301 VND, áp lực trả nợ ngắn hạn cao. Các khoản vay đều được đảm bảo bằng tiền gửi và tài sản cố định, giảm thiểu rủi ro, nhưng biến động lãi suất có thể ảnh hưởng đến chi phí tài chính.', 'Không có hàng tồn kho trong báo cáo tài chính, do đó không có rủi ro tồn kho.', 3, 'Doanh thu tăng trưởng nhẹ, lợi nhuận sau thuế tăng mạnh. Tuy nhiên, dòng tiền từ hoạt động kinh doanh âm do thay đổi vốn lưu động, cần quản lý tốt nợ ngắn hạn. Công ty có cơ cấu vốn chủ sở hữu vững chắc và đầu tư vào công ty liên kết có tiềm năng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VPR_2016_consolidated', 'VPR', 2016, 'consolidated', 'Công ty có giao dịch đáng chú ý với bên liên quan: Giám đốc Hoàng Phong Giao nhận tạm ứng 5 tỷ VND để mua cổ phần Công ty CP Xuất nhập khẩu và Đầu tư Chợ Lớn theo thỏa thuận cá nhân (số 10/INVINA/2016). Ngoài ra, Công ty thanh toán tạm ứng cổ tức cho các cổ đông lớn (Công ty CP Đầu tư Toàn Việt 41.74%, CTCK Ngân hàng Đông Á 9.64%, Công ty CP Đầu tư Vina 6.53%). Không có giao dịch bán hàng/dịch vụ cho bên liên quan.', 'Nợ vay ngắn hạn ở mức thấp 1.53 tỷ VND (cuối năm 2016), được đảm bảo bằng cầm cố tiền gửi ngân hàng 5.5 tỷ VND. Tỷ lệ nợ phải trả/vốn chủ sở hữu là 27.3/55.2 = 49.5%. Công ty có khả năng thanh toán nợ tốt từ dòng tiền hoạt động kinh doanh và tiền gửi đáo hạn. Không có nợ dài hạn từ tổ chức tín dụng.', 'Hàng tồn kho tăng mạnh từ 3.47 tỷ VND (đầu năm) lên 9.94 tỷ VND (cuối năm), chủ yếu do nguyên vật liệu tăng từ 2.81 tỷ lên 8.92 tỷ VND, phản ánh hoạt động kinh doanh mở rộng. Dự phòng giảm giá hàng tồn kho giữ nguyên ở mức 136.7 triệu VND (tỷ lệ dự phòng/tổng tồn kho chỉ 1.36%). Công trình xây dựng dở dang tăng từ 1.44 tỷ lên 1.93 tỷ VND với các dự án Thị Nghè và Phú Lâm đang triển khai.', 5, 'Công ty Cổ phần In và Thương mại Vina có sức khỏe tài chính tốt trong năm 2016. Lợi nhuận sau thuế đạt 23.24 tỷ VND, tăng mạnh so với 3.22 tỷ VND năm trước, chủ yếu từ hoạt động kinh doanh bất động sản (chuyển nhượng quyền sử dụng thuê đất tại 27-29 Hai Bà Trung mang lại doanh thu 43.48 tỷ VND). Tổng tài sản tăng từ 41.4 tỷ lên 82.6 tỷ VND. Biên lợi nhuận gộp 38.9% ở mức cao. Tuy nhiên, cần lưu ý: (1) Doanh thu tập trung lớn vào giao dịch bất động sản một lần, chưa đảm bảo tính bền vững; (2) Hàng tồn kho tăng mạnh 186%; (3) Giao dịch tạm ứng 5 tỷ VND cho Giám đốc qua thỏa thuận cá nhân tiềm ẩn rủi ro quản trị. Công ty có 58 nhân viên, hoạt động đa ngành (in ấn, thương mại, bất động sản, kho vận).'),
('VNT_2021_consolidated', 'VNT', 2021, 'consolidated', 'Giao dịch với công ty con (Công ty TNHH Giao nhận vận tải Hà Thành) chiếm tỷ trọng đáng kể (doanh thu 37,3 tỷ, mua dịch vụ 21,8 tỷ). Ngoài ra, có khoản tạm ứng cho Tổng Giám đốc với số tiền nhỏ (65 triệu). Không phát hiện giao dịch bất thường về giá hay lãi suất, nhưng cần theo dõi quy mô giao dịch nội bộ.', 'Tổng nợ vay chiếm tỷ trọng lớn trong nguồn vốn (nợ ngắn hạn ~198 tỷ, nợ dài hạn ~58,8 tỷ). Công ty sử dụng đa dạng các khoản vay ngân hàng với lãi suất từ 6,5% đến 7,5%/năm và phát hành trái phiếu chuyển đổi. Các khoản vay ngắn hạn được đảm bảo bằng tiền gửi có kỳ hạn và một số tài sản cố định. Áp lực trả nợ là đáng kể, đặc biệt với dòng tiền hoạt động kinh doanh thuần năm 2021 chỉ đạt 6,1 tỷ (năm 2020 âm 22,5 tỷ).', 'Báo cáo không trình bày chi tiết hàng tồn kho (nguyên vật liệu, thành phẩm). Các tài sản dở dang dài hạn (chi phí xây dựng cơ bản dở dang) có giá trị không lớn (147 triệu). Rủi ro tồn kho không được nhấn mạnh trong báo cáo.', 4, 'Công ty có sự tăng trưởng mạnh về doanh thu (gấp 2 lần) và lợi nhuận sau thuế (tăng 4 lần) trong năm 2021 nhờ tác động tích cực của đại dịch đến ngành logistics. Tuy nhiên, công ty phụ thuộc lớn vào nợ vay ngân hàng và trái phiếu chuyển đổi, tạo áp lực về chi phí tài chính và nghĩa vụ trả nợ. Dòng tiền hoạt động kinh doanh thuần dương nhưng thấp hơn nhiều so với lợi nhuận, cho thấy quản lý vốn lưu động cần cải thiện. Các giao dịch với bên liên quan (công ty con) chiếm tỷ trọng lớn nhưng chưa có dấu hiệu bất thường. Sức khỏe tài chính ở mức trung bình, triển vọng phụ thuộc vào diễn biến ngành và khả năng quản lý dòng tiền.'),
('VNT_2022_consolidated', 'VNT', 2022, 'consolidated', 'Doanh nghiệp có giao dịch với các bên liên quan như nhà đầu tư và ban lãnh đạo, bao gồm cung cấp dịch vụ và chia cổ tức. Không có dấu hiệu bất thường rõ ràng, nhưng cần theo dõi các giao dịch thương mại.', 'Áp lực nợ vay ngắn hạn cao với tài sản thế chấp là tiền gửi có kỳ hạn và tài sản cố định. Nợ dài hạn từ trái phiếu chuyển đổi đáo hạn vào năm 2023.', 'Rủi ro tồn kho thấp do chỉ có chi phí xây dựng dở dang với giá trị nhỏ.', 3, 'Công ty ghi nhận lỗ trong năm 2022 do doanh thu giảm 29% so với năm 2021. Tuy nhiên, công ty có tài sản và dòng tiền hoạt động kinh doanh dương. Triển vọng phụ thuộc vào sự phục hồi của ngành logistics.'),
('VNT_2020_consolidated', 'VNT', 2020, 'consolidated', 'Doanh nghiệp có giao dịch lớn với công ty con (Công ty TNHH Giao nhận vận tải Hà Thành), bao gồm cung cấp dịch vụ 39,2 tỷ và mua dịch vụ 11,3 tỷ trong năm 2020. Trả trước cho người bán lên đến 39,8 tỷ. Đây là giao dịch nội bộ tập trung, có thể tiềm ẩn rủi ro về giá chuyển giao và phụ thuộc vào hoạt động của công ty con.', 'Áp lực nợ ngắn hạn lớn với tổng nợ vay 237,9 tỷ VNĐ, lãi suất 7.5%/năm. Tỷ lệ nợ vay ngắn hạn/Vốn chủ sở hữu cao (khoảng 113%). Tài sản thế chấp bao gồm tiền gửi có kỳ hạn và TSCĐ, cho thấy tính thanh khoản bị ảnh hưởng. Công ty cần quản lý dòng tiền chặt để trả nợ đúng hạn.', 'Doanh nghiệp hoạt động trong lĩnh vực dịch vụ giao nhận vận tải, không có hàng tồn kho vật chất (nguyên liệu, thành phẩm) hay dự án xây dựng dở dang, do đó rủi ro tồn kho thấp.', 5, 'Công ty hoạt động trong lĩnh vực giao nhận vận tải, tăng trưởng doanh thu 26% trong năm 2020. Biên lợi nhuận gộp ở mức thấp (5,04%), chi phí lãi vay chiếm tỷ trọng lớn. Áp lực nợ ngắn hạn cao, nhưng Công ty có quan hệ chặt với các công ty con, liên kết. Điểm rủi ro quản trị ở mức trung bình do giao dịch tập trung với bên liên quan và cơ cấu nợ đòn bẩy cao.'),
('VNT_2019_consolidated', 'VNT', 2019, 'consolidated', 'Công ty có giao dịch tạm ứng cá nhân với Chủ tịch HĐQT (198 triệu VND, đã giảm xuống 0) và Tổng Giám đốc (141 triệu VND). Các khoản tạm ứng này là nhỏ so với quy mô tài sản. Công ty không phát hiện giao dịch bất thường lớn với bên liên quan, tuy nhiên việc cho vay/tạm ứng cá nhân cho lãnh đạo cần được kiểm soát chặt chẽ.', 'Tổng nợ ngắn hạn là 189.6 tỷ VND với lãi suất dao động từ 7.5-8%/năm. Các khoản vay được bảo đảm bằng tiền gửi có kỳ hạn và TSCĐ. Chi phí lãi vay năm 2019 giảm mạnh xuống 14.5 tỷ (so với 23.9 tỷ năm 2018) cho thấy công ty đã chủ động giảm đòn bẩy. Tuy nhiên, nợ ngắn hạn chiếm tỷ trọng lớn, tạo áp lực tái cấp vốn thường xuyên.', 'Rủi ro tồn kho thấp. Chi phí xây dựng cơ bản dở dang chỉ 147 triệu VND và không biến động, cho thấy công ty không có dự án xây dựng lớn bị ứ đọng. Doanh nghiệp hoạt động trong lĩnh vực logistics nên không có hàng tồn kho truyền thống.', 4, 'Tập đoàn Giao nhận Vận Tài Ngoại Thương có kết quả kinh doanh ổn định với doanh thu 932.8 tỷ và lợi nhuận sau thuế 4.1 tỷ VND. Biên lợi nhuận gộp đạt 5.5%. Công ty đang trong quá trình giảm đòn bẩy tài chính (nợ vay giảm từ 213.4 tỷ xuống 189.6 tỷ). Dòng tiền từ hoạt động kinh doanh dương nhưng giảm mạnh so với năm trước (3.5 tỷ vs 52.5 tỷ). Tuy nhiên, Công ty có dòng tiền đầu tư thuần dương 39 tỷ do thu hồi đầu tư. Tổng tài sản giảm nhẹ 3% từ 573.8 tỷ xuống 557.1 tỷ. Lợi nhuận cơ bản trên cổ phiếu giảm từ 817 VND xuống 303 VND do thuế TNDN truy thu 3.1 tỷ. Công ty vẫn duy trì được hoạt động liên tục và trả cổ tức 1,200 VND/cổ phiếu.'),
('VNT_2019_parent', 'VNT', 2019, 'parent', 'Có giao dịch thường xuyên với công ty con (Hà Thành) về cung cấp và mua dịch vụ. Các khoản tạm ứng cho ban lãnh đạo không lớn và đã giảm trong năm. Không phát hiện giao dịch bất thường lớn như cho vay không lãi suất hay mua bán chênh lệch bất thường.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn (khoảng 165 tỷ VND trên tổng tài sản 494 tỷ VND), tạo áp lực trả nợ đáng kể. Phần lớn nợ vay được đảm bảo bằng tiền gửi ngân hàng và một phần TSCĐ. Công ty cần quản lý dòng tiền chặt chẽ để đáp ứng nghĩa vụ trả nợ ngắn hạn.', 'Doanh nghiệp kinh doanh dịch vụ, không có hàng tồn kho truyền thống. Chỉ có dự án xây dựng dở dang với giá trị nhỏ (147 triệu VND), không tạo rủi ro tồn kho đáng kể.', 5, 'Doanh nghiệp hoạt động trong lĩnh vực giao nhận vận tải, doanh thu và lợi nhuận sau thuế năm 2019 đều giảm so với năm 2018. Cơ cấu tài chính phụ thuộc lớn vào nợ vay ngắn hạn, gây áp lực thanh khoản. Dòng tiền từ hoạt động kinh doanh vẫn dương nhưng thấp hơn nhiều so với năm trước. Doanh nghiệp có đầu tư tài chính dài hạn vào công ty con và liên kết. Cần theo dõi sát khả năng trả nợ và quản lý hiệu quả hoạt động để cải thiện biên lợi nhuận.'),
('VNT_2018_consolidated', 'VNT', 2018, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là tạm ứng cá nhân và bảo đảm cho khoản vay bằng tài sản cá nhân của ban lãnh đạo. Số tiền tạm ứng nhỏ, không có giao dịch mua bán hay cho vay không lãi suất bất thường. Rủi ro thấp.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn (213.428 tỷ VND), lãi suất dao động 7,3%-8%/năm. Công ty có tài sản thế chấp chủ yếu là tiền gửi và TSCĐ. Tiền và tương đương tiền đạt 72.840 tỷ VND, áp lực trả nợ ngắn hạn cao, cần giám sát thanh khoản.', 'Công ty hoạt động trong lĩnh vực dịch vụ logistics, không có hàng tồn kho vật chất, do đó rủi ro tồn kho không đáng kể.', 4, 'Doanh thu tăng nhưng lợi nhuận sau thuế giảm mạnh (từ 28.125 tỷ năm 2017 xuống 8.226 tỷ năm 2018) do chi phí tài chính tăng và lỗ đầu tư. Nợ ngắn hạn cao, cần cải thiện quản lý dòng tiền. Công ty có cơ cấu cổ đông rõ ràng, giao dịch bên liên quan minh bạch nhưng có rủi ro tập trung vào lãnh đạo cá nhân bảo đảm cho vay. Triển vọng trung bình, phụ thuộc vào quản lý nợ và hiệu quả hoạt động kinh doanh.'),
('VNT_2018_parent', 'VNT', 2018, 'parent', 'Công ty có giao dịch đáng kể với công ty con Công ty TNHH Giao nhận vận tải Hà Thành (100% vốn), bao gồm cung cấp dịch vụ 19.55 tỷ VND và mua dịch vụ 5.72 tỷ VND trong năm 2018. Trả trước cho người bán bên liên quan lên đến 13.49 tỷ VND. Đặc biệt, Chủ tịch HĐQT Nguyễn Xuân Giang đã dùng sổ tiết kiệm cá nhân trị giá hàng tỷ VND để đảm bảo khoản vay cho Công ty, cho thấy sự gắn kết tài chính cá nhân - doanh nghiệp. Ban lãnh đạo nhận tạm ứng tổng cộng 339.9 triệu VND. Tuy nhiên, các giao dịch này được công khai minh bạch trong thuyết minh BCTC và không có dấu hiệu bất thường rõ ràng.', 'Công ty có áp lực nợ ngắn hạn lớn với tổng dư nợ vay ngắn hạn 179.47 tỷ VND tại ngày 31/12/2018. Chi phí lãi vay trong năm 2018 là 23.20 tỷ VND, chiếm tỷ trọng đáng kể trong lợi nhuận gộp (39.59 tỷ VND). Công ty đã trả nợ gốc 750.88 tỷ VND trong năm, cho thấy quy mô vay quay vòng lớn. Các khoản vay được đảm bảo bằng tiền gửi ngân hàng, TSCĐ và sổ tiết kiệm cá nhân của Chủ tịch HĐQT. Công ty đã chuyển đổi toàn bộ trái phiếu chuyển đổi 720,000 trái phiếu (tương đương 72 tỷ VND) thành cổ phiếu, giúp giảm nợ dài hạn nhưng pha loãng vốn chủ sở hữu. Không còn nợ dài hạn tại cuối năm 2018.', 'Công ty hoạt động trong lĩnh vực giao nhận vận tải nên không có hàng tồn kho truyền thống. Khoản mục duy nhất là Chi phí xây dựng cơ bản dở dang với giá trị nhỏ (147.24 triệu VND), tăng nhẹ từ 69.34 triệu VND đầu năm. Rủi ro tồn kho không đáng kể do đặc thù ngành dịch vụ.', 5, 'VNT Logistics là công ty giao nhận vận tải ngoại thương niêm yết trên HNX. Năm 2018, doanh thu đạt 638.86 tỷ VND (tăng 11.7% so với năm 2017), nhưng lợi nhuận sau thuế giảm mạnh xuống 8.24 tỷ VND (từ 28.13 tỷ VND năm 2017) do không còn lãi bán đầu tư tài chính lớn (năm 2017 có lãi 64.35 tỷ VND). Biên lợi nhuận gộp ở mức 6.2%, đặc thù ngành logistics. Chi phí lãi vay 23.20 tỷ VND là áp lực lớn, gần bằng toàn bộ lợi nhuận gộp. Công ty đã tăng vốn từ 85.85 tỷ lên 119.49 tỷ VND thông qua phát hành cổ phiếu và chuyển đổi trái phiếu. Dòng tiền hoạt động kinh doanh dương 68.50 tỷ VND là tín hiệu tích cực. Công ty có mối quan hệ tài chính mật thiết với Chủ tịch HĐQT qua việc thế chấp tài sản cá nhân. Tổng thể, công ty có nền tảng kinh doanh ổn định nhưng cần cải thiện hiệu quả sử dụng vốn và giảm gánh nặng nợ vay.'),
('VNT_2025_parent', 'VNT', 2025, 'parent', 'Giao dịch với bên liên quan (chủ yếu là công ty con Công ty TNHH Giao nhận Vận tải Hà Thành) chiếm tỷ trọng đáng kể trong doanh thu (khoảng 11%) và chi phí. Cần giám sát tính công bằng của giá cả và điều kiện giao dịch.', 'Nợ vay ngắn hạn lớn (211.550.403.828 VND) với lãi suất từ 4% đến 7,5%/năm, tập trung ở 6 ngân hàng. Các khoản vay được đảm bảo bằng tiền gửi ngân hàng, cổ phiếu và tài sản cố định. Áp lực trả nợ trong ngắn hạn cao.', 'Công ty hoạt động trong lĩnh vực dịch vụ giao nhận vận tải, không có hàng tồn kho vật chất. Các khoản trả trước ngắn hạn và dài hạn chủ yếu liên quan đến sửa chữa kho bãi, không đáng lo ngại.', 5, 'Công ty có doanh thu và lợi nhuận ổn định trong năm 2025, với biên lợi nhuận gộp khoảng 4,5%. Tuy nhiên, công ty có cơ cấu nợ ngắn hạn lớn, phụ thuộc vào vay ngân hàng để bổ sung vốn lưu động. Giao dịch với bên liên quan, đặc biệt là công ty con, chiếm tỷ trọng lớn, cần được giám sát chặt chẽ để đảm bảo tính minh bạch. Công ty có hệ thống đầu tư tài chính dài hạn vào các công ty con và liên kết, mang lại nguồn thu nhập từ cổ tức. Tổng thể, công ty có sức khỏe tài chính ở mức trung bình, cần cải thiện quản lý dòng tiền và giảm áp lực nợ ngắn hạn.'),
('VNT_2017_consolidated', 'VNT', 2017, 'consolidated', 'Doanh nghiệp có giao dịch với công ty con và tạm ứng cho nhân sự quản lý chủ chốt, nhưng giá trị không lớn và không có dấu hiệu bất thường đáng kể.', 'Nợ vay tăng mạnh, đặc biệt là nợ ngắn hạn, áp lực trả nợ cao. Tuy nhiên, các khoản vay đều có tài sản đảm bảo đa dạng như tiền gửi, tiết kiệm cá nhân và tài sản cố định, giảm thiểu rủi ro.', 'Tồn kho dự án xây dựng dở dang có giá trị nhỏ, không đáng kể, rủi ro thấp.', 5, 'Doanh thu tăng trưởng tốt nhưng giá vốn tăng mạnh khiến lợi nhuận gộp giảm. Công ty đầu tư lớn vào tài chính dài hạn, nợ vay tăng cao để tài trợ. Tình hình tài chính ổn định nhưng cần kiểm soát chi phí và quản lý nợ hiệu quả.');
PRAGMA foreign_keys = ON;
